INSERT INTO `proyectos01` (`id`, `cod_area`, `area`, `subarea`, `origen`, `lineamiento`, `objetivos`, `cod_tipo`, `tipo`, `cod_iniciativa`, `nombre`, `etapa`, `meta_del_periodo`, `p_diseno`, `p_prefactibilidad`, `p_ejecucion`, `total`, `financiamiento`, `unidad`, `entidades_relacionadas`, `prioridad`, `cod_estado`, `estado`, `avance_actividades`, `avance_financiero`, `lat`, `lng`, `proyectos01_created`, `proyectos01_updated`, `proyectos01_user`, `proyectos01_status`, `descripcion`) VALUES
(1, 1, 'Medio Ambiente', 'Fiscalización', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Preservar y conservar los ecosistemas insulares y marinos de RMB Archipiélago Juan Fernández mediante su protección y planes de manejo ambiental que promuevan un uso sostenible, con la participación activa de la comunidad local', 'a', 'Estudio', '1.1', 'Plan de Evaluación y Mejora de Fiscalización y Regulación Ambiental para la Comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 62000, '62000.00', 'SUBDERE (Subsecretaría de Desarrollo Regional y Administrativo), Fondo Nacional de Desarrollo Regional (FNDR), Ministerio del Medio Ambiente (Fondo de Protección Ambiental), y cooperación técnica de GIZ o PNUD. ', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'Ministerio del Medio Ambiente, Superintendencia del Medio Ambiente, GORE Valparaíso, CONAF.', NULL, '1', 'En espera', '0.00', '0.00', '-33.64022830596589', '-78.83213578244326', '2025-02-07 18:12:14', '2025-02-11 21:54:12', '1', 1, 'Este estudio busca mejorar y fortalecer los protocolos de fiscalización ambiental en la comuna de Juan Fernández, así como desarrollar nuevas regulaciones y ordenanzas municipales que controlen actividades con impacto ambiental, incluyendo la introducción de especies biológicas y la tenencia responsable de mascotas. La iniciativa busca alinear la gestión ambiental de la comuna con las mejores prácticas nacionales e internacionales, asegurando una protección integral del ecosistema insular y la convivencia armónica entre fauna nativa y doméstica.'),
(2, 1, 'Medio Ambiente', 'Conservación', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Preservar y conservar los ecosistemas insulares y marinos de RMB Archipiélago Juan Fernández mediante su protección y planes de manejo ambiental que promuevan un uso sostenible, con la participación activa de la comunidad local', 'a', 'Estudio', '1.2', 'Plan Integral de Restauración de Áreas Degradadas del Archipiélago.', 'Ejecución', 'Ejecutado', NULL, NULL, 53000, '53000.00', 'FNDR, Fondo de Protección Ambiental (FPA), GEF, y cooperación internacional (PNUD, The Nature Conservancy). Incentivos de fomento al Manejo, conservación y restauración de Bosque nativo (Ley 20.283).  Compensaciones ambientales e inversiones en restauración de paisajes. Fondo Ambiental Naturaleza Chile. ', 'Unidad de gestión Ambiental Municipalidad de Juan Fernández', 'CONAF, Ministerio del Medio Ambiente, Subsecretaría de Desarrollo Regional (SUBDERE), y ONGs ambient', NULL, '1', 'En espera', '0.00', NULL, '-33.6362564823881', '-78.833805435538', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio se enfocará en identificar las áreas críticas de degradación en el archipiélago y desarrollar planes específicos de restauración ecológica, priorizando la flora y fauna endémica y fortaleciendo los servicios ecosistémicos locales. Incluye acciones de reforestación, control de especies invasoras, y monitoreo ambiental para evaluar la efectividad de las intervenciones y asegurar la recuperación sostenible de los ecosistemas.'),
(3, 1, 'Medio Ambiente', 'Conservación', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Preservar y conservar los ecosistemas insulares y marinos de RMB Archipiélago Juan Fernández mediante su protección y planes de manejo ambiental que promuevan un uso sostenible, con la participación activa de la comunidad local', 'b', 'Programa', '1.3', 'Capacitación en Técnicas de Restauración Ecológica y Conservación para Funcionarios y Comunidad. ', 'Ejecución', 'Ejecutado', NULL, NULL, 58000, '58000.00', 'Fondo de Protección Ambiental (FPA). FNDR (Fondo Nacional de Desarrollo Regional). Cooperación Internacional (PNUD, BID, GIZ).', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'Ministerio del Medio Ambiente: Asesoría técnica y financiamiento. CONAF: Apoyo en la restauración de', NULL, '1', 'En espera', '0.00', NULL, '-33.6414736579322', '-78.83367348226994', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Este programa desarrolla capacidades técnicas de los funcionarios municipales y miembros de la comunidad de Juan Fernández en restauración ecológica y conservación ambiental, promoviendo la gestión participativa y sostenible de los ecosistemas terrestres y marinos del archipiélago. Las capacitaciones incluirán conocimientos sobre control de especies invasoras, reforestación con flora nativa, técnicas de monitoreo ambiental, y manejo de áreas protegidas.'),
(4, 1, 'Medio Ambiente', 'Conservación', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Preservar y conservar los ecosistemas insulares y marinos de RMB Archipiélago Juan Fernández mediante su protección y planes de manejo ambiental que promuevan un uso sostenible, con la participación activa de la comunidad local', 'b', 'Programa', '1.4', 'Jardines Comunitarios de Flora Nativa.', 'Ejecución', 'Ejecutado', NULL, NULL, 53000, '53000.00', 'Presupuesto Municipal, Fondo de Protección Ambiental (FPA). FNDR (Fondo Nacional de Desarrollo Regional). Cooperación Internacional (PNUD, BID, GIZ). ', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández en Coordinación con SECPLA', 'FPA, Ministerio Medio Ambiente. CONAF. Fondo Nacional de proyectos01 Escolares (FONAPES), Ministerio', NULL, '1', 'En espera', '0.00', NULL, '-33.63432316319503', '-78.83551577024782', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Este programa busca crear jardines comunitarios de flora nativa en áreas urbanas del archipiélago, involucrando a la comunidad en la reforestación y preservación de especies endémicas. Los jardines servirán como espacios de encuentro comunitario, fomentarán la educación ambiental y ayudarán a restaurar la biodiversidad local, alineándose con la necesidad de mitigar los efectos del cambio climático y la erosión del suelo en el territorio'),
(5, 1, 'Medio Ambiente', 'Gestión de residuos', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Poner en marcha en el territorio una gestión integral de residuos que minimice su impacto ambiental y promueva la economía circular en el archipiélago.', 'a', 'Estudio', '1.5', 'Plan Estratégico para la Gestión Integral de Residuos Sólidos en Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 55000, '55000.00', 'FNDR (Fondo Nacional de Desarrollo Regional). Fondo de Reciclaje del Ministerio del Medio Ambiente. Fondo de Protección Ambiental (FPA). Cooperación Internacional (PNUD, BID, GIZ). ', 'Unidad de gestión Ambiental Municipalidad de Juan Fernández', 'Ministerio del Medio Ambiente: Asesoramiento técnico y fondos de reciclaje. Superintendencia del Med', NULL, '1', 'En espera', '0.00', NULL, '-33.64087350632562', '-78.83295426539304', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Desarrollar un sistema de gestión integral de residuos sólidos adaptado a las particularidades del archipiélago, que incluya acciones de recolección diferenciada, reciclaje, compostaje y reducción de residuos en origen. Este plan estará alineado con los principios de economía circular y sustentabilidad integrando las iniciativas en curso del \"Sistema Tecnológico para una Gestión Sostenible e Integral de Residuos en Juan Fernández\" y “Sistema de gestión de Residuos Sólidos Domiciliarios y Asimilables para la comuna de Juan Fernández”, la cual apunta a la implementación del tratamiento y transformación de residuos sólidos en productos reutilizables. Se buscará integrar las capacidades de estas iniciativas existentes para maximizar la eficiencia y sostenibilidad de la gestión de residuos.'),
(6, 1, 'Medio Ambiente', 'Gestión de residuos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Poner en marcha en el territorio una gestión integral de residuos que minimice su impacto ambiental y promueva la economía circular en el archipiélago.', 'c', 'Proyecto', '1.6', 'Sistema de gestión de Residuos Sólidos Domiciliarios y Asimilables para la comuna de Juan Fernández (Desafíos Públicos 2024) ', 'Ejecución', 'Ejecutado', NULL, NULL, 307348, '307348.00', 'PMB SUBDERE', 'SECPLA/ Unidad de gestión Ambiental', 'SUBDERE', NULL, '4', 'En licitación', '0.00', NULL, '-33.64032015540753', '-78.83229267442958', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Adquisición de un nuevo horno incinerador de residuos, desarrollo de la infraestructura asociada al mismo, construcción de nueva infraestructura para el pretratamiento de RSD e institucionales, recuperando entre un 20 a 30% de los RSD. Se pretende que el nuevo sistema de gestión de RSD e institucionales sea más completo y seguro del que se tiene actualmente por medio del proceso de incineración en la Comuna de Juan Fernández contribuyendo de forma significativa al proceso de distribución final de los residuos.'),
(7, 1, 'Medio Ambiente', 'Gestión de residuos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Poner en marcha en el territorio una gestión integral de residuos que minimice su impacto ambiental y promueva la economía circular en el archipiélago.', 'c', 'Proyecto', '1.7', 'Sistema Tecnológico para una Gestión Sostenible e Integral de Residuos en Juan Fernández (Desafíos Públicos 2024) ', 'Ejecución', 'Ejecutado', NULL, NULL, 310000, '310000.00', 'ANID / Desafíos públicos', 'SECPLA/ Unidad de gestión Ambiental', 'SEREMI Medio Ambiente', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.6371309128503', '-78.83631723050931', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Desarrollo de un sistema tecnológico integral para la gestión de residuos sólidos en la comuna, orientado a procesar y transformar los residuos sólidos de la isla, promoviendo una economía circular que permita la elaboración de productos y/o materiales a partir de residuos. La iniciativa incluye el tratamiento in situ y está diseñada para adaptarse a las particularidades del contexto insular de Juan Fernández. '),
(8, 1, 'Medio Ambiente', 'Gestión de residuos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Poner en marcha en el territorio una gestión integral de residuos que minimice su impacto ambiental y promueva la economía circular en el archipiélago.', 'c', 'Proyecto', '1.8', 'Estaciones de Recepción y Reducción volumétrica de material reciclable, comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 70357, '70357.00', 'PMB SUBDERE', 'Unidad de Gestión Ambiental', 'SEREMI Medio Ambiente', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.638324759435996', '-78.83477424369298', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Implementar un sistema de 38 puntos verdes sectoriales en la Comuna de Juan Fernández, que apoyen a la disminución de residuos a disponer en el vertedero comunal, además de otorgar 550 packs de contenedores domiciliarios para promover la segregación en origen de los residuos domiciliarios sólidos. Todo lo anterior, para facilitar el proceso de reciclaje de elementos prioritarios según lo indicado en la Ley N°20.920. Implementar una red de 38 puntos de reciclaje para integrar el reciclaje en la comunidad:  Minimizar la generación de los RSD en la comuna Otorgar 550 contenedores domiciliarios a cada una de los domicilios y servicios públicos de la comuna. Concientizar y educar a la población en materias medio ambiental y la separación de residuos en su origen. Disminuir la cantidad de RSD transportados a disposición final en Vertedero Municipal y aumentar la cantidad de RDS reciclados, que son trasportados vía marítima a la Comuna de Valparaíso para su posterior tratamiento.'),
(9, 1, 'Medio Ambiente', 'Gestión de residuos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Poner en marcha en el territorio una gestión integral de residuos que minimice su impacto ambiental y promueva la economía circular en el archipiélago.', 'b', 'Programa', '1.9', 'Fomentando el Desarrollo Sostenible de Nuestras Islas', 'Ejecución', 'Ejecutado', NULL, NULL, 16700, '16700.00', 'Fondo para el Reciclaje 2025 MMA ', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'SEREMI Medio Ambiente', NULL, '3', 'Postulada a financiamiento', '0.00', NULL, '-33.64236994682075', '-78.8338240825437', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Programa de educación ambiental centrado en la gestión de residuos, que incluirá actividades de sensibilización y capacitación sobre el reciclaje, la correcta disposición de desechos y el uso adecuado de puntos limpios. El programa se llevará a cabo a través de talleres, charlas y actividades prácticas dirigidas a la comunidad y organizaciones sociales. Se difundirá información sobre la Ley REP (Responsabilidad Extendida del Productor) y la prohibición del uso de bolsas plásticas, así como sobre la Estrategia Nacional de Residuos Orgánicos (ENRO). Se capacitará a los participantes en el manejo y separación de residuos en sus hogares. Las actividades se realizarán en espacios comunitarios, escuelas y otros lugares públicos dentro de la comuna de Juan Fernández, facilitando el acceso a toda la población.'),
(10, 1, 'Medio Ambiente', 'Gestión de riesgos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Disponer de estrategias y planes para la gestión del riesgo de desastres en el Archipiélago.', 'a', 'Estudio', '1.10', 'Desarrollo del Plan de Acción Comunal de Cambio Climático de la comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 34000, '34000.00', 'BID-SEREMI Medio Ambiente', 'Unidad de gestión Ambiental', 'SEREMI Medio Ambiente', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.642206374797965', '-78.83611666136214', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Desarrollar el Plan de Acción Comunal de Cambio Climático en la comuna de Juan Fernández de la región de Valparaíso, en coordinación con las autoridades y equipos regionales, municipales y Comité Regionales de Cambio Climático, y en cumplimiento con el Artículo 12 de la Ley Marco de Cambio Climático.'),
(11, 1, 'Medio Ambiente', 'Gestión de riesgos', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Disponer de estrategias y planes para la gestión del riesgo de desastres en el Archipiélago.', 'a', 'Estudio', '1.11', 'Plan de Gestión de Riesgos de Desastres en Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 81000, '81000.00', 'FNDR, FPA, SUBDERE, Fondo Verde del Clima (GFC), GEF.', 'Unidad de gestión Ambiental Municipalidad de Juan Fernández', 'SENAPRED, Ministerio Medio Ambiente, Superintendencia del Medio Ambiente, Ministerio de Obras Públic', NULL, '1', 'En espera', '0.00', NULL, '-33.64056468450905', '-78.83655703479323', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio orientado a identificar los principales riesgos climáticos que afectan al archipiélago, tales como inundación por tsunami, remoción en masa e incendios forestales, inundaciones pluviales, fluviales y costeras, temporales con fuertes vientos y lluvias, entre otros. Por esto se necesita contar un plan de gestión de riesgos que incluya medidas de mitigación y adaptación, así como sistemas de alerta temprana y fortalecimiento de la infraestructura resiliente para proteger tanto a la comunidad como a los ecosistemas locales. Alineado con los resultados de la iniciativa BID Código CH-T1293-P003 de apoyo al Desarrollo del PACCC para la comuna, el que se encuentra en etapa de ejecución, planificada su aprobación para junio de 2025. Y con el Convenio para la Elaboración del Plan Comunal de Reducción de Riesgos de Desastres.'),
(12, 1, 'Medio Ambiente', 'Gestión de riesgos', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Disponer de estrategias y planes para la gestión del riesgo de desastres en el Archipiélago.', 'b', 'Programa', '1.12', 'Talleres de Educación y Capacitación en Gestión de Riesgos para la Comunidad.', 'Ejecución', 'Ejecutado', NULL, NULL, 45000, '45000.00', 'Presupuesto Municipal. Fondo Nacional de Desarrollo Regional (FNDR). Fondo de Protección Ambiental (FPA) (para gestión del riesgo ambiental). Cooperación Internacional (GIZ, PNUD, BID).', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'SENAPRED: Asesoría técnica en gestión de emergencias y simulacros. Ministerio del Interior: Coordina', NULL, '1', 'En espera', '0.00', NULL, '-33.63924936567984', '-78.83074967992584', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Talleres de educación y capacitación en gestión de riesgos para la comunidad.'),
(13, 1, 'Medio Ambiente', 'Gestión de riesgos', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Disponer de estrategias y planes para la gestión del riesgo de desastres en el Archipiélago.', 'b', 'Programa', '1.13', 'Prevención y Respuesta Comunitaria ante Incendios en Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 69000, '69000.00', 'FNDR, Fondo de Protección Ambiental (FPA), cooperación internacional (GIZ, BID, PNUD).', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'SENAPRED: Apoyo técnico en gestión de riesgos y simulacros. Gobierno Regional de Valparaíso: Coordin', NULL, '1', 'En espera', '0.00', NULL, '-33.63850173667672', '-78.83270424410719', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Prevención y respuesta comunitaria ante incendios en Juan Fernández.'),
(14, 1, 'Medio Ambiente', 'Gestión de riesgos', 'Cartera Actual', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Disponer de estrategias y planes para la gestión del riesgo de desastres en el Archipiélago.', 'b', 'Programa', '1.14', 'Convenio para la elaboración del Programa Comunal de Reducción de Riesgos de Desastres.', 'Ejecución', 'Ejecutado', NULL, NULL, 7000, '7000.00', 'SENAPRED', 'Unidad de gestión Ambiental en coordinación con SECPLA ', 'SENAPRED', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63613465508046', '-78.8316845270492', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Convenio entre la Municipalidad de Juan Fernández y SENAPRED, para la colaboración y transferencia de recursos financieros para financiar la elaboración del Plan Comunal para la Reducción de riesgos de Desastres. '),
(15, 1, 'Medio Ambiente', 'Conservación', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Posicionar a la comuna como un nicho de investigación científica a nivel internacional poniendo en valor el territorio como un laboratorio natural para la investigación en conservación, ecología y hábitat armónico con los bienes naturales.', 'b', 'Programa', '1.15', 'Alianza Internacional para la Conservación y Sostenibilidad.', 'Ejecución', 'Ejecutado', NULL, NULL, 91000, '91000.00', 'Fondo Verde del Clima (Green Climate Fund). GEF (Global Environment Facility). Cooperación Internacional (PNUD, BID, GIZ). The Nature Conservancy (TNC) y otras ONG ambientales.', 'Unidad de Gestión Ambiental Municipalidad de Juan Fernández', 'Ministerio del Medio Ambiente: Asesoramiento y articulación internacional. Gobierno Regional de Valp', NULL, '1', 'En espera', '0.00', NULL, '-33.635761630386256', '-78.83347138116257', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Alianza internacional para la conservación y sostenibilidad.'),
(16, 1, 'Medio Ambiente', 'Conservación', 'PLADECO', '1. Un ecosistema preservado y conservado que pone en valor su biodiversidad y equilibra la protección estricta con el manejo sostenible de sus recursos', 'Posicionar a la comuna como un nicho de investigación científica a nivel internacional poniendo en valor el territorio como un laboratorio natural para la investigación en conservación, ecología y hábitat armónico con los bienes naturales.', 'c', 'Proyecto', '1.16', 'Centro de Investigación Ambiental y Conservación de la Reserva de la Biosfera Archipiélago Juan Fernández, Etapa de prefactibilidad.', 'Prefactibilidad', 'Ejecutado pre / factibilidad', NULL, 60000, NULL, '60000.00', 'FNDR (Fondo Nacional de Desarrollo Regional).  GEF (Global Environment Facility). Cooperación Internacional (PNUD, BID, GIZ).', 'Unidad de Gestión ambiental en coordinación con SECPLA', 'SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.640509679411004', '-78.83138774768318', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto busca desarrollar un Centro de Investigación Ambiental y Conservación, que funcionará como un laboratorio natural para el estudio de la biodiversidad y los ecosistemas insulares del archipiélago. Además, este centro promoverá la colaboración científica internacional y fortalecerá las capacidades locales en gestión ambiental, educación y conservación.'),
(17, 1, 'Medio Ambiente', 'Energía', 'Cartera Actual', '2. Una comunidad que transita hacia una autonomía energética sustentable y de bajo impacto.', 'Desarrollar una matriz energética sostenible, reduciendo la dependencia de combustibles fósiles y fortaleciendo la resiliencia ambiental y económica del territorio.', 'a', 'Estudio', '1.17', 'Elaboración de la estrategia Energética Local de la comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 59992, '59992.00', 'PMB SUBDERE', 'SECPLA  ', 'Agencia de la Sostenibilidad Energética. Seremi Ministerio de Energía', NULL, '4', 'En licitación', '0.00', NULL, '-33.639397671612215', '-78.83384585832555', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio para el desarrollo de la Estrategia Energética (EEL) de la comuna de Juan Fernández, que cuente con la participación de actores relevantes, reconociendo los potenciales de Generación y eficiencia Energética, a partir de la correcta identificación de los recursos y tomando en cuenta la visión de desarrollo de la comuna plasmada en el PLADECO, y la promoción de participación de actores locales en el desarrollo energético de la comuna.  (duración 120 días corridos)'),
(18, 1, 'Medio Ambiente', 'Energía', 'PLADECO', '2. Una comunidad que transita hacia una autonomía energética sustentable y de bajo impacto.', 'Desarrollar una matriz energética sostenible, reduciendo la dependencia de combustibles fósiles y fortaleciendo la resiliencia ambiental y económica del territorio.', 'c', 'Proyecto', '1.18', 'Microred de Energía Renovable para el Archipiélago, Etapa de prefactibilidad.', 'Prefactibilidad', 'Ejecutado', 62000, NULL, NULL, '62000.00', 'FNDR (Fondo Nacional de Desarrollo Regional). Fondo de Energías Renovables del Ministerio de Energía. Cooperación Internacional (GIZ, BID, PNUD).', 'SECPLA', 'Ministerio de Energía /SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.64181459527429', '-78.83471506876627', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Alineado con los resultados del Estudio Estrategia Energética Local, el proyecto está dirigido a implementar una micro red de energía renovable en el archipiélago de Juan Fernández para garantizar una autonomía energética sostenible. Esta red aprovechará los recursos renovables locales, como energía solar, eólica y sistemas de almacenamiento, permitiendo reducir la dependencia de combustibles fósiles, disminuir emisiones y mejorar la resiliencia energética de la comunidad.'),
(19, 1, 'Medio Ambiente', 'Energía', 'PLADECO', '2. Una comunidad que transita hacia una autonomía energética sustentable y de bajo impacto.', 'Desarrollar una matriz energética sostenible, reduciendo la dependencia de combustibles fósiles y fortaleciendo la resiliencia ambiental y económica del territorio.', 'c', 'Proyecto', '1.19', 'Recambio de luminarias públicas por luminarias de energía renovable, etapa de diseño.', 'Diseño', 'Ejecutado', 19000, NULL, NULL, '19000.00', 'FNDR - SUBDERE. Fondo de Energías Renovables del Ministerio de Energía. Cooperación Internacional (GIZ, BID, PNUD). Fondo de Acceso Energético.', 'SECPLA en coordinación con Unidad de Gestión Ambiental y DOM', 'SUBDERE/ Ministerio de Energía', NULL, '1', 'En espera', '0.00', NULL, '-33.64093491813265', '-78.83556583066641', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto busca formular una propuesta para el recambio de las luminarias públicas actuales por luminarias alimentadas por energías renovables. La etapa de diseño definirá las alternativas tecnológicas, los costos estimados, la localización de las intervenciones, y el modelo de operación y mantenimiento del sistema. Dando cumplimiento a la Nueva Norma Lumínica (D.S. N°1/2022 MMA). Asegurando la protección y minimizando el impacto sobre las aves marinas del territorio.'),
(20, 1, 'Medio Ambiente', 'Energía', 'PLADECO', '2. Una comunidad que transita hacia una autonomía energética sustentable y de bajo impacto.', 'Desarrollar un modelo de gestión energética comunitaria que garantice el acceso equitativo a tecnologías de energías limpias, fomentando la participación y apropiación local.', 'b', 'Programa', '1.20', 'Capacitación comunitaria en eficiencia energética autoconsumo con implementación en hogares e instituciones de la comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 70000, '70000.00', 'FNDR (Fondo Nacional de Desarrollo Regional). Fondo de Energías Renovables del Ministerio de Energía. Cooperación Internacional (GIZ, BID, PNUD). Agencia de la Sustentabilidad- MINVU.', 'Unidad de Gestión Ambiental en coordinación con SECPLA y DOM', 'Ministerio de Energía: Apoyo técnico y financiamiento. Gobierno Regional de Valparaíso: Coordinación', NULL, '1', 'En espera', '0.00', NULL, '-33.640341604089556', '-78.83098989418694', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Capacitación comunitaria en eficiencia energética autoconsumo con implementación en hogares e instituciones de la comuna de Juan Fernández.'),
(21, 2, 'Sistema Productivo', 'Pesca artesanal', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Creación y desarrollo de subproductos derivados de la pesca artesanal, diversificando la oferta local para fortalecer la identidad del archipiélago.', 'a', 'Estudio', '2.1', 'Estudio para la diversificación comercial de la langosta y otros productos pesqueros.', 'Ejecución', 'Ejecutado', NULL, NULL, 59000, '59000.00', 'SERNAPESCA, FNDR, Presupuesto Municipal.', 'Unidad de Pesca, Municipalidad de Juan Fernández.', 'SERNAPESCA', NULL, '1', 'En espera', '0.00', NULL, '-33.636985731545636', '-78.83327163359387', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Realizar un estudio para identificar oportunidades de mercado para los productos pesqueros y definir estrategias para aprovechar estas oportunidades, con un programa de implementación. Se debe considerar que la diversificación comercial puede requerir la diversificación del producto.'),
(22, 2, 'Sistema Productivo', 'Emprendimiento', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Creación y desarrollo de subproductos derivados de la pesca artesanal, diversificando la oferta local para fortalecer la identidad del archipiélago.', 'c', 'Proyecto', '2.2', 'Centro de innovación y emprendimiento para la pesca artesanal y actividades relacionadas, etapa de prefactibilidad.', 'Prefactibilidad', 'Ejecutado / pre factibilidad', NULL, 70000, NULL, '70000.00', 'CORFO, FIC FNDR, INDESPA', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández en coordinación con SECPLA', 'CORFO, SERNAPESCA', NULL, '1', 'En espera', '0.00', NULL, '-33.635373276509114', '-78.83384423963837', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Realizar estudios exhaustivos que proporcionen la base para diseñar un centro que impulse la sostenibilidad económica de la pesca artesanal en el largo plazo. Un Centro de Innovación y Emprendimiento para la Pesca Artesanal es un espacio multifuncional que integra investigación, capacitación, innovación tecnológica, y fomento del emprendimiento. Ofrece recursos y apoyo a los pescadores y emprendedores para mejorar sus prácticas, agregar valor a sus productos, facilitar la adopción de nuevas tecnologías y prácticas en el sector pesquero artesanal.'),
(23, 2, 'Sistema Productivo', 'Infraestructura productiva', 'Cartera Actual', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Creación y desarrollo de subproductos derivados de la pesca artesanal, diversificando la oferta local para fortalecer la identidad del archipiélago.', 'c', 'Proyecto', '2.3', 'Taller-carpintería reparación de embarcaciones artesanales', 'Diseño', 'RS Ejecución', NULL, NULL, 300000, '300000.00', 'No identificada', 'SECPLA Municipalidad de Juan Fernández', 'SERNAPESCA', NULL, '2', 'Formulada', '0.00', NULL, '-33.63493948371039', '-78.83064685912929', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto consiste en la elaboración y posterior ejecución de un taller para la reparación de embarcaciones artesanales, ubicado en calle Circunvalación s/n, en el sector productivo ZPR según PRC. El objetivo principal, es dotar de la infraestructura necesaria, al principal sector productivo local, para el fortalecimiento del desarrollo pesquero artesanal a través de la carpintería de ribera, fortalecer y preservar las tradiciones y mantener la memoria y patrimonio material de este oficio centenario del archipiélago Juan Fernández. '),
(24, 2, 'Sistema Productivo', 'Equipamiento', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Creación y desarrollo de subproductos derivados de la pesca artesanal, diversificando la oferta local para fortalecer la identidad del archipiélago.', 'c', 'Proyecto', '2.4', 'Adquisición de Sistema de comunicaciones radiales operadores pesqueros y turísticos de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 54000, '54000.00', 'FNDR, SERNAPESCA, FRIL, SUBDERE', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández', 'SERNAPESCA', NULL, '1', 'En espera', '0.00', NULL, '-33.641209515863466', '-78.83578952744286', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Dotar a la flota pesquera, a los operadores turísticos y a instituciones fiscalizadoras de estas actividades de sistemas de comunicaciones modernos en frecuencias VHF. Este proyecto radial se considera la prioridad para el programa pesca municipal 2025-2029, que tiene como objetivo principal velar por la seguridad marítima de los pescadores artesanales y comunidad terrestre del archipiélago Juan Fernández (isla Robinson Crusoe, isla Santa Clara e isla Alejandro Selkirk). Además, se considera un excelente instrumento para la fiscalización de las Áreas Marinas Costeras de Múltiples usos (AMCP-MU) considerando los protocolos de vigilancias para las ACMU (SERNAPESCA), quienes son los mismos pescadores que han impulsado la creación de protección marina y quieren ser parte de la fiscalización de las áreas frente a la amenaza de la pesca industrial. Este proyecto de comunicaciones radiales lo respalda la Armada de Chile y el Servicio Nacional de Pesca Local.'),
(25, 2, 'Sistema Productivo', 'Equipamiento', 'Cartera Actual', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Creación y desarrollo de subproductos derivados de la pesca artesanal, diversificando la oferta local para fortalecer la identidad del archipiélago.', 'c', 'Proyecto', '2.5', 'Normalización del Box de pescadores.', 'Ejecución', 'Ejecutado', NULL, NULL, 500000, '500000.00', 'No identificada', 'SECPLA Municipalidad de Juan Fernández', 'SERNAPESCA', NULL, '2', 'Formulada', '0.00', NULL, '-33.64115745198831', '-78.83310146382513', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Ampliar el box de pescadores como una forma de fomentar la capacidad operacional del borde costero y ordenamiento territorial, considerando la reposición y mejoramiento de la infraestructura del box de pescadores e implementación de una estrategia de manejo de residuos provenientes de la pesca artesanal.'),
(26, 2, 'Sistema Productivo', 'Diversificación', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Diversificar la economía con turismo sostenible, la producción artesanal y la gastronomía de productos locales.', 'a', 'Estudio', '2.7', 'Plan de desarrollo para la diversificación productiva del archipiélago sectores turismo, artesanías y alimentos preparados.', 'Ejecución', 'Ejecutado', NULL, NULL, 84500, '84500.00', 'FNDR, Subsecretaría de Turismo, Presupuesto Municipal', 'Unidad de Fomento Productivo Municipalidad Juan Fernández', 'SERNATUR, SERCOTEC, CORFO', NULL, '1', 'En espera', '0.00', NULL, '-33.6405472458929', '-78.83262562988425', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Realizar estudios para formular un plan de desarrollo productivo local considerando evaluar la frontera productiva de las actividades, los factores de competitividad a desarrollar, definir el perfil de los negocios, las condiciones para acceder a los mercados, definir las características de un espacio para la innovación colaborativa, y la infraestructura habilitante. El plan debe identificar las acciones requeridas para la puesta en valor de los recursos, el desarrollo del capital humano, la inversión y el emprendimiento en los negocios.'),
(27, 2, 'Sistema Productivo', 'Empleabilidad', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Diversificar la economía con turismo sostenible, la producción artesanal y la gastronomía de productos locales.', 'a', 'Estudio', '2.8', 'Estudio de perfiles ocupaciones y empleabilidad de la población de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 44000, '44000.00', 'FNDR, SENCE, Municipalidad de Juan Fernández', 'Unidad de Fomento Productivo Municipalidad Juan Fernández', 'SENCE, Dirección del Trabajo', NULL, '1', 'En espera', '0.00', NULL, '-33.63889012110811', '-78.83485983895103', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio de perfiles ocupaciones y empleabilidad de la población de Juan Fernández.'),
(28, 2, 'Sistema Productivo', 'Emprendimiento', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Diversificar la economía con turismo sostenible, la producción artesanal y la gastronomía de productos locales.', 'b', 'Programa', '2.9', 'Programa de formación de los jóvenes en oportunidades de emprendimiento a nivel local.', 'Ejecución', 'Ejecutado', NULL, NULL, 136000, '136000.00', 'FNDR, SERCOTEC, CORFO, Municipalidad de Juan Fernández', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández', 'SERCOTEC, CORFO, SLEP', NULL, '1', 'En espera', '0.00', NULL, '-33.64130125351096', '-78.83638100153317', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Programa de formación para desarrollar capacidades de emprendimiento en jóvenes en edades tempranas enfocado en el desarrollo de habilidades blandas, pensamiento creativo, competencias empresariales básicas y actitudes hacia la innovación y el trabajo en equipo. '),
(29, 2, 'Sistema Productivo', 'Comercialización', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Diversificar la economía con turismo sostenible, la producción artesanal y la gastronomía de productos locales.', 'b', 'Programa', '2.10', 'Programa agencia local de turismo.', 'Ejecución', 'Ejecutado', NULL, NULL, 151100, '151100.00', 'FNDR, Subsecretaría de Turismo, Presupuesto Municipal, SUBDERE, Fondos puntuales para zonas ZOIT, SERCOTEC, MINISTERIO DE AGRICULTURA (INDAP - TURISMO RURAL)', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández', 'SERNATUR', NULL, '1', 'En espera', '0.00', NULL, '-33.63574937916637', '-78.83225769037684', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Creación de una agencia local definiendo modelo de negocios que sea un mix entre una operadora turística que organiza y gestiona tours y experiencias, y una agencia de viajes que actúa como intermediaria en la venta de paquetes turísticos locales. '),
(30, 2, 'Sistema Productivo', 'Gobernanza', 'Cartera Actual', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Diversificar la economía con turismo sostenible, la producción artesanal y la gastronomía de productos locales.', 'c', 'Proyecto', '2.11', 'Centro integral de desarrollo turístico CIDETUR.', 'Ejecución', 'Ejecutado', NULL, NULL, 59108, '59108.00', 'PMU SUBDERE', 'SECPLA Municipalidad de Juan Fernández', 'SERNATUR', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.641118601117135', '-78.83064694547731', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto consiste en la construcción del Centro Integral de Desarrollo Turístico del Archipiélago Juan Fernández (CIDETUR), el cual estará emplazado en la continuación de la Plaza de Armas en el centro del Poblado San Juan Bautista. Esta ubicación permite que el CIDETUR, sea un elemento integral en la zona productiva y de mayor flujo peatonal y vehicular de la comuna. Esta obra considera ser un espacio mucho más persuasivo, atractivo y que permita realizar asesoramiento personal a los visitantes de acuerdo con sus intereses y motivaciones de viaje, satisfacer las necesidades de información relacionadas con la oferta turística y cultura del destino y cubrir otra serie de necesidades frecuentes en el visitante relacionadas con la propia actividad turística (compra de insumos, áreas de descanso, uso de internet, temas de salud y otros). La infraestructura se traspasará para su operación al gremio de turismo.'),
(31, 2, 'Sistema Productivo', 'Comercialización', 'PLADECO', '1. Una economía local consolidando actividades económicas sostenibles y de valor agregado basadas en la riqueza natural de su maritorio.', 'Desarrollar un sello de origen para el archipiélago que identifique sus servicios turísticos y productos a nivel internacional.', 'b', 'Programa', '2.12', 'Programa sello de origen para certificación de servicios turísticos Archipiélago de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 46000, '46000.00', 'SERNATUR – FNDR, CORFO, Presupuesto municipal, Agencia de la sustentabilidad', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández', 'SERNATUR, INAPI', NULL, '1', 'En espera', '0.00', NULL, '-33.64160922885595', '-78.83069383348555', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Desarrollar una certificación o distintivo oficial que se otorgará a productos turísticos locales (tangibles e intangibles) para reconocer su autenticidad, calidad y su vinculación con el archipiélago. Este sello garantizará que el producto turístico está directamente relacionado con la identidad cultural, geográfica o histórica de la comuna, y que cumple con estándares de calidad establecidos.  El sello de origen asegura al turista que la experiencia o servicio que está adquiriendo ha sido cuidadosamente diseñado para ofrecer un alto nivel de calidad, seguridad y sostenibilidad.'),
(32, 3, 'Hábitat Urbano', 'Planificación', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'a', 'Estudio', '3.1', 'Estudio hidrogeológico y de mecánica de suelos.', 'Ejecución', 'Ejecutado', NULL, NULL, 47900, '47900.00', 'SUBDERE (PMB)', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.640481022943284', '-78.83316389112208', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Obtener antecedentes técnicos para proyectar obras de mejoramiento en las captaciones y obras de regulación, consistentes en estanques de hormigón armado semienterrados con estándar DOH. El apartado hidrológico tiene como foco estudiar las precipitaciones, considerando una proyección a 30 años, en el contexto de cambio climático, estimando las variaciones de caudal en 5 puntos de captación. El apartado geológico se refiere a una revisión bibliográfica, de modo de contar con una caracterización de la localidad. El estudio de mecánica de suelos tiene como objetivo generar información en 5 puntos donde se prevé la proyección de obras de almacenamiento.'),
(33, 3, 'Hábitat Urbano', 'Saneamiento', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'a', 'Estudio', '3.2', 'Estudio de calidad de agua y tratamiento.', 'Ejecución', 'Ejecutado', NULL, NULL, 18500, '18500.00', 'SUBDERE (PMB)', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64303410940845', '-78.83446167898697', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Analizar las características físicas, químicas y bacteriológicas del agua cruda y tratada que se consume en el poblado según la normativa vigente (Nch 409), con el fin de establecer una línea base para proyectar mejoramientos al sistema de tratamiento. El apartado de tratamiento tiene como objetivo analizar la infraestructura existente y proponer mejoramientos, o bien un rediseño completo.'),
(34, 3, 'Hábitat Urbano', 'Saneamiento', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'b', 'Programa', '3.3', 'Asistencia técnica para alternativas de inversión en consumo humano y saneamiento', 'Ejecución', 'Ejecutado', NULL, NULL, 82800, '82800.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63541909239863', '-78.83688912969097', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Teniendo en cuenta las dificultades técnicas y económicas a las que se enfrenta la comuna, la Municipalidad de Juan Fernández, a través del Programa de Mejoramiento de Barrios (PMB) de la Subsecretaría de Desarrollo Regional y Administrativo (SUBDERE), gestionó la contratación de profesionales ingenieros civiles para conformar un equipo de Asistencia Técnica con el fin de desarrollar proyectos01 de infraestructura sanitaria. Este trabajo se enmarca en una visión más global que considera la regularización del sistema de agua de consumo humano y alcantarillado para la localidad de San Juan Bautista, proceso que es llevado a cabo por la Dirección de Obras hidráulicas (DOH) del MOP.'),
(35, 3, 'Hábitat Urbano', 'Agua potable', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'c', 'Proyecto', '3.4', 'Sectorización e interconexión de Redes de Agua Comunal.', 'Ejecución', 'Ejecutado', NULL, NULL, 81585, '81585.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63818388175603', '-78.83257804643601', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Tiene como objetivo robustecer la red actual de agua comunal mediante la instalación de válvulas e interconexiones hidráulicas, de manera de otorgar al sistema la capacidad de sectorizar los tramos de redes que requieran reparaciones, sin cortar el suministro al resto de los usuarios. Las interconexiones hidráulicas entre sistemas y al interior de estos, permitirán generar redundancia, de manera que el agua podrá distribuirse por distintos circuitos para llegar a un mismo punto, otorgando alternativas de abastecimiento cuando deban ejecutarse obras en las redes principales.'),
(36, 3, 'Hábitat Urbano', 'Agua potable', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'c', 'Proyecto', '3.5', 'Mejoramiento de redes de distribución de agua, comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 190347, '190347.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63616322266311', '-78.83216055718148', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Tiene como objetivo robustecer la red actual de distribución de los 2 sistemas mediante la instalación de válvulas, el reemplazo de tramos de tubería de materialidad asbesto cemento (rocalit) por tuberías de materialidad HDPE y la instalación de tuberías de materialidad HDPE.'),
(37, 3, 'Hábitat Urbano', 'Agua potable', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'c', 'Proyecto', '3.6', 'Mejoramiento de captaciones y aducciones, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 300000, '300000.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.639165108742816', '-78.83073421410063', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto tiene como objetivo robustecer las dos captaciones y la aducción del sistema que actualmente permite la distribución de agua comunal en los sectores La Pólvora y Lord Anson.'),
(38, 3, 'Hábitat Urbano', 'Agua potable', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE1. Garantizar el acceso seguro y equitativo a agua potable para la comuna.', 'c', 'Proyecto', '3.7', 'Mejoramiento y ampliación del sistema de agua potable Servicio Sanitario Rural Juan Fernández. Etapa diseño.', 'Diseño', 'Diseño ejecutado y obra en licitación', 420000, NULL, NULL, '420000.00', 'DOH-MOP y Municipalidad', 'SECPLA, DOM.', 'DOH-MOP', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63864114688003', '-78.83322613608665', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto consiste en elaborar el diseño de ingeniería para la construcción del sistema de agua potable en la localidad de San Juan Bautista, y asimismo elaborar el perfil para postular a su ejecución de acuerdo con la metodología sectorial vigente en el Sistema Nacional de Inversiones (MDSF), de manera de contar con un servicio que cumpla con la normativa vigente, lo cual constituye una aspiración histórica de la comunidad. Existe el compromiso de financiamiento del diseño adquirido por la DOH según oficio ordinario del 8 de agosto de 2024. ');
INSERT INTO `proyectos01` (`id`, `cod_area`, `area`, `subarea`, `origen`, `lineamiento`, `objetivos`, `cod_tipo`, `tipo`, `cod_iniciativa`, `nombre`, `etapa`, `meta_del_periodo`, `p_diseno`, `p_prefactibilidad`, `p_ejecucion`, `total`, `financiamiento`, `unidad`, `entidades_relacionadas`, `prioridad`, `cod_estado`, `estado`, `avance_actividades`, `avance_financiero`, `lat`, `lng`, `proyectos01_created`, `proyectos01_updated`, `proyectos01_user`, `proyectos01_status`, `descripcion`) VALUES
(39, 3, 'Hábitat Urbano', 'Saneamiento', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE2. Avanzar en la solución para la consolidación de un sistema de aguas servidas para proteger la salud pública y el entorno natural.', 'c', 'Proyecto', '3.8', 'Solución de disposición de aguas servidas de población Santa Clara y El Escocés', 'Ejecución', 'Ejecutado', NULL, NULL, 190345, '190345.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63954176137646', '-78.835280907778', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'La entrega del proyecto a los beneficiarios fue concretada en julio del 2008. Cada vivienda quedó provista de un sistema particular de infiltración, compuesto por cámaras desgrasadoras y cortajabón, una fosa y un pozo de infiltración. Debido a que el sistema presentó problemas de afloramiento en los lotes por saturación del terreno y uso no adecuado de este tipo de soluciones, la iniciativa tiene por objetivo mejorar el sistema de disposición en las poblaciones Santa Clara y El Escocés, donde existen puntos críticos de afloramiento de aguas servidas. Con ello, aportar en el mejoramiento de la situación de infraestructura sanitaria en el área poblada de San Juan Bautista en Isla Robinson Crusoe. La solución propuesta es la instalación de un colector público de PVC, cámaras de inspección en base a módulos prefabricados, cámaras de unión domiciliaria y tramos de colector internos en cada lote. Para la disposición final del agua servida se considera una planta de tratamiento de lodos activados con un sistema de aireación extendida, incluyendo etapas de decantación, aireación, sedimentación, cloración y decloración, antes de verter el efluente sobre un lecho de bolones en las mismas quebradas en las que actualmente operan los pozos.'),
(40, 3, 'Hábitat Urbano', 'Saneamiento', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE2. Avanzar en la solución para la consolidación de un sistema de aguas servidas para proteger la salud pública y el entorno natural.', 'c', 'Proyecto', '3.9', 'Solución de disposición de aguas servidas población Los Cipreses y GEA.', 'Ejecución', 'Ejecutado', NULL, NULL, 330000, '330000.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64243266127025', '-78.83251799411589', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Mejorar el sistema de disposición en las poblaciones Los Cipreses y GEA, donde existen puntos críticos de afloramiento de aguas servidas. Con ello, aportar en el mejoramiento de la situación de infraestructura sanitaria en el área poblada de San Juan Bautista en Isla Robinson Crusoe. Se instalarán colectores públicos de PVC, cámaras desgrasadoras en cada lote, cámaras de inspección en base a módulos prefabricados, cámaras de unión domiciliaria y uniones domiciliarias, de modo de que las viviendas queden conectadas a la obra desde su ejecución.'),
(41, 3, 'Hábitat Urbano', 'Saneamiento', 'PLADECO', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE2. Avanzar en la solución para la consolidación de un sistema de aguas servidas para proteger la salud pública y el entorno natural.', 'c', 'Proyecto', '3.10', 'Construcción sistema de alcantarillado Servicio Sanitario Rural Juan Fernández. Etapa prefactibilidad.', 'Prefactibilidad', 'Diseño ejecutado', NULL, 107500, NULL, '107500.00', 'DOH-MOP, SUBDERE y Municipalidad', 'SECPLA, DOM.', 'DOH-MOP, SUBDERE.', NULL, '1', 'En espera', '0.00', NULL, '-33.64191314802593', '-78.83257604170007', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto consiste en elaborar un perfil de prefactibilidad de acuerdo con la metodología sectorial vigente en el Sistema Nacional de Inversiones (MDSF), para que la localidad de San Juan Bautista pueda contar con un sistema integral de alcantarillado que permita erradicar los impactos sobre el medioambiente derivados de los afloramientos de aguas servidas, originados en el colapso de los sistemas individuales que existen actualmente. Se trata de definir la solución técnico-económica más adecuada para la instalación del servicio de alcantarillado (redes y PTAS).'),
(42, 3, 'Hábitat Urbano', 'Espacio público', 'PLADECO', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'a', 'Estudio', '3.11', 'Plan de mejoramiento y estandarización de calzadas, localidad de San Juan Bautista, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado y obras en licitación', NULL, NULL, 150360, '150360.00', 'FNDR (financiamiento del estudio), MINVU (Programa de Pavimentos Participativos), SUBDERE (PMU).', 'SECPLA', 'GORE, SUBDERE, MOP, MINVU.', NULL, '1', 'En espera', '0.00', NULL, '-33.6344289457949', '-78.83271013152692', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio tiene por objetivo realizar un levantamiento del estado de situación de las calles de la localidad de San Juan Bautista para su mejoramiento progresivo, considerando la disparidad de sus características físicas y de diseño, contribuyendo a la calidad e identidad urbanas y a mejorar las condiciones de seguridad para la movilidad vehicular. Considera una propuesta de diseño técnico tipo de pavimentos, un análisis y propuesta de alumbrado público, la regularización de perfiles y nombres de calles y la elaboración de una cartera priorizada de intervenciones con evaluación de costos en base a un plan de inversiones. Se considera relevante establecer un proceso de participación ciudadana orientado a discutir en torno a los proyectos01 prioritarios y al significado de un diseño cultural y ambientalmente adecuado. Asimismo, se debe analizar su relación con las iniciativas que se incorporen al Plan Especial de Zonas Extremas (PDZE). Este estudio es complementario con el Plan de mejoramiento y estandarización de aceras, además de los proyectos01 en curso que está ejecutando la Municipalidad.'),
(43, 3, 'Hábitat Urbano', 'Espacio público', 'PLADECO', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'a', 'Estudio', '3.12', 'Plan de mejoramiento y estandarización de aceras, localidad de San Juan Bautista, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado y obras en licitación', NULL, NULL, 150360, '150360.00', 'FNDR (financiamiento del estudio), MINVU (Programa de Pavimentos Participativos), SUBDERE (PMU).', 'SECPLA', 'GORE, SUBDERE, MOP, MINVU.', NULL, '1', 'En espera', '0.00', NULL, '-33.638927964879684', '-78.83473540997984', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio tiene por objetivo realizar un levantamiento del estado de situación de las veredas de la localidad de San Juan Bautista para su mejoramiento progresivo, considerando las brechas observadas y la disparidad de sus características físicas y de diseño, contribuyendo a la calidad e identidad urbanas y a mejorar las condiciones de seguridad para la movilidad peatonal. Asimismo, considera una propuesta tipo de diseño técnico de pavimentos, la elaboración de una cartera priorizada de intervenciones, una evaluación de costos y un plan de inversiones. Se considera relevante establecer un proceso de participación ciudadana orientado a discutir en torno a los proyectos01 prioritarios y al significado de un diseño cultural y ambientalmente adecuado. Asimismo, se debe analizar su relación con las iniciativas que se incorporen al Plan Especial de Zonas Extremas (PDZE).Este estudio es complementario con el Plan de mejoramiento y estandarización de calzadas, además de los proyectos01 en curso que está ejecutando la Municipalidad.'),
(44, 3, 'Hábitat Urbano', 'Vialidad urbana', 'PLADECO', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'a', 'Estudio', '3.13', 'Evaluación y mejoramiento de puentes peatonales y vehiculares, Poblado de San Juan Bautista. ', 'Ejecución', 'Ejecutado', NULL, NULL, 190820, '190820.00', 'MOP, FNDR y MINVU (financiamiento del estudio).', 'SECPLA', 'GORE, MOP.', NULL, '1', 'En espera', '0.00', NULL, '-33.64027568914259', '-78.83325633629619', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio tiene por objetivo estandarizar los puentes del poblado, evaluando sus condiciones de seguridad a nivel de su estructura, iluminación y requerimientos de barreras, generando una imagen identitaria en base a un modelo de diseño y, en conjunto con las iniciativas de aceras y calzadas, vendría a completar la movilidad dentro de San Juan Bautista. Se considera relevante establecer un proceso de participación ciudadana orientado a discutir en torno a los proyectos01 prioritarios. También, analizar su relación con las iniciativas que se incorporen al Plan Especial de Zonas Extremas (PZDE). Este estudio es complementario con los proyectos01 en curso que está ejecutando la Municipalidad.'),
(45, 3, 'Hábitat Urbano', 'Vialidad urbana', 'PLADECO', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.14', 'Normalización y pavimentación calle La Pólvora.', 'Diseño', 'Obra ejecutada', 62000, NULL, NULL, '62000.00', 'Programa de Pavimentos Participativos MINVU', 'SECPLA, DOM.', 'SERVIU Valparaíso', NULL, '1', 'En espera', '0.00', NULL, '-33.634859494526594', '-78.8321377453857', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto, que proviene de los diagnósticos realizados en el marco del Programa Pequeñas Localidades del MINVU para la localidad de San Juan Bautista en la comuna de Juan Fernández, consiste en la elaboración del perfil de diseño para la pavimentación de 448 metros lineales de este eje que tiene carácter de vía colectora y eje fundacional dentro del barrio más antiguo, entre calle Larraín Alcalde (Alfred Von Rodt) y fondo de la calle. El objetivo es conectar una zona residencial del poblado con la parte baja de la comuna donde se emplaza el puerto, el área deportiva y diversos equipamientos. Además, es vía de evacuación de emergencia y permite acceder al Parque Nacional.'),
(46, 3, 'Hábitat Urbano', 'Vialidad urbana', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.15', 'Construcción huella de hormigón, sector Circunvalación El Castillo.', 'Ejecución', 'Ejecutado', NULL, NULL, 85455, '85455.00', 'GORE (FNDR)', 'SECPLA', 'GORE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.642909088428446', '-78.83065494054688', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consolidación progresiva de la red vial comunal, en particular en el área poblada de San Juan Bautista en Isla Robinson Crusoe, lo que deriva de los déficits identificados de pavimentación y mejoramiento general de la red.'),
(47, 3, 'Hábitat Urbano', 'Vialidad urbana', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.16', 'Construcción huella de hormigón, sector La Cruz (etapa 3)', 'Ejecución', 'Ejecutado', NULL, NULL, 82542, '82542.00', 'GORE (FNDR)', 'SECPLA', 'GORE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63629636877035', '-78.83192524472744', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consolidación progresiva de la red vial comunal, en particular en el área poblada de San Juan Bautista en Isla Robinson Crusoe, lo que deriva de los déficits identificados de pavimentación y mejoramiento general de la red.'),
(48, 3, 'Hábitat Urbano', 'Vialidad urbana', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.17', 'Conservación de Huellas y Accesos en Vicente González y Alfred Von Rodt.', 'Ejecución', 'Ejecutado', NULL, NULL, 700000, '700000.00', 'MINVU (Programa Pequeñas Localidades)', 'SECPLA', 'MINVU', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.634568302522226', '-78.83379220962526', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consolidación progresiva de la red vial comunal, en particular en el área poblada de San Juan Bautista en Isla Robinson Crusoe, lo que deriva de los déficits identificados de pavimentación y mejoramiento general de la red, mejorando lo existente y ajustándose a la normativa de accesibilidad universal.'),
(49, 3, 'Hábitat Urbano', 'Vialidad urbana', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.18', 'Construcción huella de hormigón, calles Juan Fernández y Doctor Johow.', 'Ejecución', 'Ejecutado', NULL, NULL, 81545, '81545.00', 'GORE (FNDR)', 'SECPLA', 'GORE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63495552778326', '-78.83381440560943', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consolidación progresiva de la red vial comunal, en particular en el área poblada de San Juan Bautista en Isla Robinson Crusoe, lo que deriva de los déficits identificados de pavimentación y mejoramiento general de la red.'),
(50, 3, 'Hábitat Urbano', 'Vialidad urbana', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.19', 'Construcción Pasaje Los Piratas.', 'Ejecución', 'Ejecutado', NULL, NULL, 358000, '358000.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63597405396183', '-78.83426503025684', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consolidación progresiva de la red vial comunal, en particular en el área poblada de San Juan Bautista en Isla Robinson Crusoe, lo que deriva de los déficits identificados de pavimentación y mejoramiento general de la red.'),
(51, 3, 'Hábitat Urbano', 'Transporte urbano', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE3. Establecer una red vial y peatonal segura y accesible que conecte de manera eficiente del poblado de San Juan Bautista, fomentando la movilidad urbana sostenible.', 'c', 'Proyecto', '3.20', 'Sistema de transporte terrestre subsidiado para la localidad de San Juan Bautista.', 'Ejecución', 'Ejecutado', NULL, NULL, NULL, '0.00', 'MTT', 'MTT', 'MTT', NULL, '2', 'Formulada', '0.00', NULL, '-33.63622144071841', '-78.83375693274041', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El servicio circulará por las principales vías de la localidad de San Juan Bautista, pasando por lugares de interés como el Liceo Bicentenario, la municipalidad y principales oficinas públicas. Se trata de un vehículo tipo minibús con tracción 4x4 equipado con aire acondicionado, con capacidad para 17 pasajeros y tarifa diferenciada para adultos ($300) y estudiantes ($100), junto con gratuidad para personas mayores de 65 años. Operará con una frecuencia semanal de 35 viajes redondos (la licitación fue publicada el 2 de julio de 2024).'),
(52, 3, 'Hábitat Urbano', 'Planificación', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE4. Desarrollar un sistema eficiente de gestión de aguas lluvias que prevenga inundaciones, proteja las quebradas y esteros, mitigando los riesgos ambientales asociados.', 'a', 'Estudio', '3.21', 'Diagnóstico plan maestro de evacuación de aguas lluvias localidad de San Juan Bautista, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 132800, '132800.00', 'FNDR, MINVU (financiamiento del estudio).', 'SECPLA', 'GORE, MINVU, SUBDERE.', NULL, '1', 'En espera', '0.00', NULL, '-33.64122326963787', '-78.83296497671714', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio consiste en elaborar el plan maestro de aguas lluvias de acuerdo con la metodología sectorial vigente, para que la localidad de San Juan Bautista pueda contar con un sistema de drenaje y evacuación de aguas lluvias, reduciendo de esta forma los riesgos asociados al deslizamiento de material en los cerros, quebradas y vías e impactos sobre la transitabilidad vehicular y peatonal.  Considera el análisis de la situación de los esteros como parte del sistema de evacuación, sobre la base del cuidado ambiental de la red de esteros y recuperación de quebradas, con alternativas de solución en coherencia con la topografía. Incluye, asimismo, el análisis de alternativas de acumulación y utilización de aguas lluvias para el riego de los espacios públicos de Juan Bautista.'),
(53, 3, 'Hábitat Urbano', 'Espacio público', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'a', 'Estudio', '3.22', 'Plan maestro mejoramiento y modernización red de espacios públicos localidad de San Juan Bautista, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado y obras licitadas', NULL, NULL, 249700, '249700.00', 'FNDR, MOP.', 'SECPLA, DOM.', 'DOH-MOP.', NULL, '1', 'En espera', '0.00', NULL, '-33.639349376781546', '-78.83540820853847', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio está orientado al mejoramiento de la calidad de los espacios públicos existentes en la localidad de San Juan Bautista como bienes nacionales de uso público bajo administración municipal, mediante la incorporación de componentes de diseño inteligente de alto estándar, que permitan disponer de áreas universalmente accesibles, homogéneas, seguras y sustentables económica y ambientalmente. Es importante, desde la perspectiva del diseño y gestión inteligente de los espacios, la incorporación de tecnologías digitales para la operación de dispositivos como, por ejemplo, el accionamiento de iluminación, cámaras de seguridad, información de especies a través de códigos QR escaneables con el celular, sensores de sonido para indicar precaución para el caso de discapacidad visual, entre varios otros que pueden progresivamente incorporarse para un espacio público accesible y de calidad, y energías renovables no convencionales (ERNC), como por ejemplo sistemas solares para iluminación, considerando luminarias con respeto ambiental de aves (fardelas) y cielos. Incluye el análisis de señalética identificatoria de especies y seguridad. El plan considera intervenir sobre todos los espacios de la localidad, hayan sido o no objeto de proyectos01 recientes, bajo el concepto de normalizar las características de accesibilidad y sustentabilidad.'),
(54, 3, 'Hábitat Urbano', 'Planificación', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'a', 'Estudio', '3.23', 'Actualización Plan Regulador Comunal de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 280000, '280000.00', 'MINVU', 'SECPLA', 'MINVU.', NULL, '1', 'En espera', '0.00', NULL, '-33.63447468144977', '-78.83082838358261', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El PRC vigente data de 1983, con una actualización realizada en 1997, aprobada por RES 31-4-216 y publicada en el Diario Oficial con fecha 03.05.2002. Se realizó posteriormente una nueva modificación, publicada en el Diario Oficial con fecha 06.07.2013. Se requiere actualizar el estado de la planificación de la comuna y sus sectores poblados en base a la normativa vigente, considerando la problemática ambiental y los equilibrios necesarios para un desarrollo que tome en cuenta los impactos sobre el entorno.'),
(55, 3, 'Hábitat Urbano', 'Planificación', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'a', 'Estudio', '3.24', 'Plan Maestro de Desarrollo Territorial Rada La Colonia en Isla Alejandro Selkirk, comuna de Juan Fernández.', 'Ejecución', 'En ejecución', NULL, NULL, 132800, '132800.00', 'FNDR, SUBDERE PMU y PMB, MINVU Pequeñas Localidades, Programa de Espacio Público.', 'SECPLA', 'GORE, SUBDERE, MINVU', NULL, '1', 'En espera', '0.00', NULL, '-33.634466235066476', '-78.83162153126283', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Se requiere evaluar las necesidades específicas de la población que habita temporalmente la isla Alejandro Selkirk por motivos de trabajo, considerando, de una parte, su aporte a la economía nacional y, de otra, el hecho de insertarse en un Parque Nacional, lo que dificulta el acceso a proyectos01 de inversión. Uno de los principales desafíos es, en consecuencia, abordar la necesidad y posibilidad de desafectar el área de su condición de Parque Nacional, para lo cual ya se han estado realizando gestiones. Un plan maestro, como instrumento, permite realizar los análisis orientados a establecer un ordenamiento del territorio de Selkirk en base a una imagen objetivo, en coherencia con las actividades económicas y forma de vida de esta comunidad de pescadores que, por tantos años se ha dedicado a la actividad de la pesca de la langosta, entre otros productos del mar, lo que deberá acompañarse de un plan de gestión para lograr un alineamiento institucional en torno a los proyectos01 prioritarios para sus habitantes.'),
(56, 3, 'Hábitat Urbano', 'Planificación', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'a', 'Estudio', '3.25', 'Actualización de la situación de propiedad de los terrenos públicos y privados sin uso actual y plan de saneamiento, áreas pobladas comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 178700, '178700.00', 'FNDR', 'SECPLA', 'GORE, MINVU-SERVIU, MBN.', NULL, '1', 'En espera', '0.00', NULL, '-33.64030514716319', '-78.83623968732675', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El estudio se orienta a consolidar información para contar con una base de datos actualizada sobre la oferta de terrenos en los sectores poblados de la comuna, de manera de avanzar en el proceso de gestión y planificación de inversiones destinadas al desarrollo urbano y de vivienda con el apoyo de las instituciones regionales pertinentes. Asimismo, prevé realizar un registro de ocupación del espacio público para su regularización (líneas oficiales) y elaborar un plan de saneamiento predial para su implementación en el tiempo. El estudio es relevante para la toma de decisiones y para la gestión público-privada, de manera de avanzar en el desarrollo urbano y mejorar las condiciones de acceso de la población a los bienes urbanos. También es importante considerar el trabajo realizado por el Ministerio de Bienes Nacionales a través del “Diagnóstico de propiedades fiscales en la comuna de Juan Fernández” y del “Programa de Transferencia Gestión Territorial en la comuna de Juan Fernández”. También es importante el alineamiento de este trabajo con el proceso de actualización del Plan Regulador Comunal, estudiando la situación de ocupación y uso de suelo del área recreativa, el límite a la expansión urbana, la habilitación de nuevos terrenos para el desarrollo urbano y habitacional y la capacidad de carga asociada a la relación entre el área actualmente ocupada y el Parque Nacional.'),
(57, 3, 'Hábitat Urbano', 'Gestión territorial', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'b', 'Programa', '3.26', 'Programa Transferencia Gestión Territorial en la comuna de Juan Fernández 2024-2026.', 'Ejecución', 'Ejecutado', NULL, NULL, 173160, '173160.00', 'GORE Valparaíso', 'Ministerio de Bienes Nacionales', 'Ministerio de Bienes Nacionales', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.637701900630006', '-78.83288245241724', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Orientado a fortalecer la gestión y administración de terrenos fiscales en zonas extremas. Corresponde a un catastro de los inmuebles fiscales en Juan Fernández, encaminado hacia una administración más eficiente y una mejor utilización de estos terrenos que a largo plazo para avanzar en la normalización de las propiedades fiscales en la comuna, buscando regularizar la ocupación de inmuebles fiscales y apoyar la planificación urbana.'),
(58, 3, 'Hábitat Urbano', 'Espacio público', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'c', 'Proyecto', '3.27', 'Construcción paseo costero Bahía Cumberland', 'Ejecución', 'Ejecutado', NULL, NULL, 18000000, '18000000.00', 'DOP-MOP', 'DOP-MOP', 'DOP-MOP', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63984038529766', '-78.83087173348713', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Proyecto en 3 etapas, cuya longitud es de 1.772 metros lineales, que considera ejecutar obras entre los sectores El Palillo (proyecto ya ejecutado en este sector) y El Faro, en el área costera de Bahía Cumberland. '),
(59, 3, 'Hábitat Urbano', 'Espacio público', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'c', 'Proyecto', '3.28', 'Construcción espacios públicos barriales del poblado de San Juan Bautista.', 'Ejecución', 'Ejecutado', NULL, NULL, 320000, '320000.00', 'MINVU, Programa Pequeñas Localidades.', 'SECPLA', 'MINVU', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63762329971992', '-78.83580070661627', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Corresponde a la construcción de 3 plazas sobre sitios eriazos en distintos sectores de la localidad de San Juan Bautista que se encuentran en estado de abandono. Son áreas de encuentro y esparcimiento para desarrollo de actividades recreativas en que se integran elementos característicos e identitarios de la cultura local, además de elementos naturales propios del maritorio.'),
(60, 3, 'Hábitat Urbano', 'Espacio público', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'c', 'Proyecto', '3.29', 'Construcción de accesos, senderos y miradores en monumentos nacionales históricos con protección fiscal en ZOIT Robinson Crusoe.', 'Ejecución', 'Ejecutado', NULL, NULL, 60000, '60000.00', 'SUBDERE (PMU)', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64252982479583', '-78.83128999889946', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Se inscribe dentro de las postulaciones para el mejoramiento urbano de ZOIT impulsado conjuntamente entre la SUBDERE y la Subsecretaría de Turismo, en favor del desarrollo y perfeccionamiento de los territorios para potenciar el destino, atraer turistas y apoyar la economía local. Tiene como propósito construir y mejorar el principal acceso al Monumento Histórico Nacional Cuevas de los Patriotas y el acceso secundario al monumento histórico nacional fuerte Santa Bárbara, en San Juan Bautista, complementándolos con zonas de descanso, dado las pendientes que se presentan en el área, así como también la creación de miradores que invitan al disfrute hacia bahía Cumberland. Contempla también intervenciones de mejoramiento de un puente, rampa, nivelación y mejoramiento de bifurcaciones, de un sendero de madera, de un sendero de hormigón y barandas de seguridad.'),
(61, 3, 'Hábitat Urbano', 'Espacio público', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'c', 'Proyecto', '3.30', 'Mejoramiento de plazas y espacios públicos, Poblado San Juan Bautista.', 'Ejecución', 'Ejecutado', NULL, NULL, 103959, '103959.00', 'GORE (FRIL)', 'SECPLA', 'GORE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64208897761753', '-78.83685973958295', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto forma parte de un conjunto de iniciativas que buscan avanzar en la consolidación de la red de plazas, entregando zonas de esparcimiento para la comunidad del poblado e invitando a utilizar de buena manera los espacios.  Actualmente se postuló el mejoramiento de dos plazas, La Verbena y La Cruz, ambas colindantes a la vía Circunvalación La Cruz que conecta con todo el cordón superior vehicular del poblado y que se encuentran en proceso de licitación, manteniendo la infraestructura existente como juego e instalando pasarelas de tránsito accesible y zonas de avistamiento de aves, fomentando el cuidado del medio ambiente y la valoración de los entornos naturales. '),
(62, 3, 'Hábitat Urbano', 'Espacio público', 'Cartera Actual', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE5. Planificar la mejora y ampliación de la infraestructura urbana, asegurando su calidad y funcionalidad, en armonía con el entorno natural y cultural del territorio.', 'c', 'Proyecto', '3.31', 'Construcción zona recreativa comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 248104, '248104.00', 'Programa Concursable de Espacios Públicos (MINVU). Programa de Recuperación de Barrios (MINVU). Programa de Mejoramiento Urbano (PMU, SUBDERE). Programa Pequeñas Localidades (MINVU).', 'SERVIU, SECPLA', 'SEREMI de Vivienda Región de Valparaíso', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.6368952363051', '-78.83472971793944', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Se trata de un espacio público con carácter cívico deportivo, que se asienta en la zona baja del poblado. Se plantea como solución mejorar el espacio existente mediante la consolidación de recorridos que integren las distintas instalaciones deportivas y recreativas y la transformación de los sitios eriazos en pequeñas plazas, incorporando accesibilidad universal, iluminación y equipamiento urbano, interviniendo una superficie efectiva de 14.140 m2.  Busca consolidar, en el único sector dentro del límite urbano vigente, que cumple con las características para albergar equipamiento deportivo y recreativo, un espacio con vocación deportiva dentro de la trama urbana de la localidad, que albergará todas las actividades deportivas, sociales y culturales de la comuna.'),
(63, 3, 'Hábitat Urbano', 'Vivienda', 'PLADECO', '2. Un desarrollo urbano planificado, con equipamiento de calidad, armónico con el paisaje, y con disponibilidad para el asentamiento de las familias.', 'OE6. Impulsar un desarrollo habitacional sostenible que integre la identidad cultural y respete el entorno natural del archipiélago.', 'a', 'Estudio', '3.32', 'Plan de desarrollo habitacional sustentable con pertinencia cultural, localidad de San Juan Bautista, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 98000, '98000.00', 'FNDR, MINVU.', 'SECPLA, DOM.', 'GORE, MINVU.', NULL, '1', 'En espera', '0.00', NULL, '-33.636863937490546', '-78.83455427087152', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Generar alternativas habitacionales sustentables en sitio nuevo o residente en base a prototipos de diseño de arquitectura que respondan a las principales características socioculturales de las áreas que componen el territorio comunal, avanzando, de esta forma, en la implementación de soluciones habitacionales diversificadas de acuerdo con las diferencias en la composición familiar y de ingreso, que den cobertura adecuada a la demanda de sus residentes en cantidad y calidad de vivienda en la localidad de San Juan Bautista. Incluye la actualización de la situación de demanda habitacional, considerando que ya se han creado nuevos comités de vivienda y existe un proceso de tomas de terrenos en áreas no permitidas para dicho uso. Es relevante analizar alternativas de gestión habitacional con la reactivación de la entidad patrocinante municipal y la inclusión de profesionales para su fortalecimiento.'),
(64, 3, 'Hábitat Urbano', 'Saneamiento', 'Cartera Actual', '1. Una red sanitaria, vial y peatonal habilitantes del desarrollo urbano.', 'OE2. Avanzar en la solución para la consolidación de un sistema de aguas servidas para proteger la salud pública y el entorno natural.', 'a', 'Estudio', '3.33', 'Estudio de solución de disposición de aguas servidas para sedes deportivas, comuna de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 14000, '14000.00', 'SUBDERE-PMB', 'SECPLA', 'SUBDERE', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63567185106735', '-78.83101469344909', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'En la localidad de San Juan Bautista existen cuatro clubes deportivos y sociales que constituyen los principales puntos de encuentro de la comunidad. En las dependencias de los clubes tienen lugar celebraciones, comidas a beneficio, actividades infantiles y de tercera edad, contando todas con infraestructura asimilable a uso de restaurant. Debido a las condiciones de saturación de los terrenos, se requiere una solución de saneamiento sanitario adecuada a la demanda de uso de las sedes, que puedan implementarse en espacios reducidos y en que se considere alternativas no convencionales ecológicamente sustentables.'),
(65, 4, 'Logística y Accesibilidad', 'Gestión territorial', 'PLADECO', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Garantizar una conectividad adecuada y accesible que permita la integración eficiente del archipiélago con el continente y su dinamismo económico y social.', 'a', 'Estudio', '4.1', 'Plan de fortalecimiento de la red de transporte marítimo y aéreo hacia la isla Robinson Crusoe, comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 78000, '78000.00', 'FNDR, MTT', 'Municipalidad', 'Subsecretaría de Transportes, SEREMI MTT, DAP-MOP, DOP-MOP, GORE.', NULL, '1', 'En espera', '0.00', NULL, '-33.64170854681282', '-78.83638809842081', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Orientado a evaluar alternativas para mejorar la frecuencia, calidad y seguridad en el transporte de personas y bienes, a la vez que diseñar un plan de gestión que incluya el establecimiento de una comisión regional de transporte con participación de la municipalidad como eje conductor, para avanzar en los objetivos y resultados en base a una hoja de ruta. La iniciativa es complementaria con el estudio Análisis de alternativas de movilidad marítima en el Archipiélago de Juan Fernández.'),
(66, 4, 'Logística y Accesibilidad', 'Infraestructura portuaria', 'Cartera Actual', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Garantizar una conectividad adecuada y accesible que permita la integración eficiente del archipiélago con el continente y su dinamismo económico y social.', 'c', 'Proyecto', '4.2', 'Ampliación infraestructura portuaria Bahía Cumberland, archipiélago Juan Fernández.', 'Ejecución', 'Ejecutado', 815446, NULL, NULL, '815446.00', 'DOP-MOP', 'DOP-MOP', 'DOP-MOP', NULL, '2', 'Formulada', '0.00', NULL, '-33.63457951766171', '-78.83470504422029', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Orientado a mejorar los estándares de funcionamiento de esta infraestructura pública para prestar servicios bajo condiciones óptimas para el atraque y permanencia de naves, con obras de reparación del muelle existente y ampliación de la zona de atraque. Los trabajos consisten, principalmente, en alargue del muelle existente en 52 metros, elementos náuticos, defensas, escalas, iluminación y conservación de fundas de hormigón en pilotes existentes e instalación de una grúa de mayor tonelaje en el muelle, con una capacidad de 20 – 25 toneladas, entre otras intervenciones puntuales.'),
(67, 4, 'Logística y Accesibilidad', 'Infraestructura aeroportuaria', 'Cartera Actual', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Garantizar una conectividad adecuada y accesible que permita la integración eficiente del archipiélago con el continente y su dinamismo económico y social.', 'c', 'Proyecto', '4.3', 'Reposición Umbral 14 aeródromo Robinson Crusoe.', 'Ejecución', 'Ejecutado', NULL, NULL, 1061993, '1061993.00', 'DAP-MOP', 'DAP-MOP', 'DAP-MOP', NULL, '2', 'Formulada', '0.00', NULL, '-33.63416202511534', '-78.83187148135892', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Proyecto orientado a mantener la continuidad operacional del aeródromo, dado el hundimiento presente en el umbral 14 de la pista de aterrizaje y despegue que se agrava progresivamente, pudiendo eventualmente impedir los viajes aéreos si no se realiza algún tipo de inversión.'),
(68, 4, 'Logística y Accesibilidad', 'Planificación', 'PLADECO', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Gestionar soluciones de accesibilidad y movilidad marítima entre las islas.', 'a', 'Estudio', '4.4', 'Estudio análisis de alternativas de movilidad marítima en el Archipiélago de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 127000, '127000.00', 'FNDR', 'SEREMI MTT', 'GORE', NULL, '1', 'En espera', '0.00', NULL, '-33.63095941947115', '-78.82901787757874', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Se orienta a mejorar la conectividad marítima entre las islas que componen el Archipiélago, de manera de optimizar el trabajo asociado a la pesca, esencial para su desarrollo socioeconómico, evaluando alternativas para la incorporación de naves y desarrollo de rutas que mejoren la frecuencia, calidad y seguridad en el transporte de personas y bienes. Un tema relevante es la inclusión de infraestructura portuaria en Isla Selkirk, mediante la incorporación de un nuevo muelle de atraque. La iniciativa es complementaria con el estudio Plan de gestión institucional para el fortalecimiento de la red de transporte marítimo y aéreo hacia la isla Robinson Crusoe, comuna de Juan Fernández.'),
(69, 4, 'Logística y Accesibilidad', 'Infraestructura portuaria', 'PLADECO', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Gestionar soluciones de accesibilidad y movilidad marítima entre las islas.', 'c', 'Proyecto', '4.5', 'Construcción de muelle Rada La Colonia en Isla Alejandro Selkirk, comuna de Juan Fernández – Etapa de Prefactibilidad.', 'Prefactibilidad', 'Diseño ejecutado', NULL, 145600, NULL, '145600.00', 'DOP-MOP.', 'SECPLA, DOM.', 'DOP-MOP.', NULL, '1', 'En espera', '0.00', NULL, '-33.63577981555765', '-78.83278549559924', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto consiste en elaborar un perfil de prefactibilidad de acuerdo con la metodología sectorial vigente en el Sistema Nacional de Inversiones (MDSF), para que la comunidad de pescadores de Rada La Colonia pueda contar con infraestructura de atraque en la bahía donde se emplaza la caleta de pescadores para facilitar el movimiento de sus naves, disminuyendo de esta forma los riesgos en las faenas asociadas a su actividad. Este proyecto beneficia a la comunidad que reside temporalmente en Isla Selkirk entre los meses de septiembre y mayo, debido a que facilita la llegada de naves con víveres de consumo cotidiano. También genera beneficios para los visitantes que se trasladan hacia esta isla desde Bahía Cumberland en San Juan Bautista, Isla Robinson Crusoe. El proyecto debiera considerar los estudios tendientes a determinar los requerimientos y características de la infraestructura a modo general a nivel de programa de áreas, como camino de acceso, escalas, explanadas y rampas, barandas, defensas, muros, longitud del muelle, iluminación y otras necesidades.'),
(70, 4, 'Logística y Accesibilidad', 'Infraestructura productiva', 'PLADECO', '1. Un sistema de transporte eficiente y flexible entre las islas del archipiélago y con el continente que permite disminuir las brechas provocadas por el aislamiento territorial.', 'Gestionar soluciones de accesibilidad y movilidad marítima entre las islas.', 'c', 'Proyecto', '4.6', 'Construcción de galpón portuario, etapa perfil de diseño', 'Perfil', 'Ejecutado / Diseño', 20000, NULL, NULL, '20000.00', 'FNDR, SERNAPESCA, Presupuesto Municipal', 'Unidad de Fomento Productivo Municipalidad de Juan Fernández', 'SERNAPESCA', NULL, '1', 'En espera', '0.00', NULL, '-33.63542775528055', '-78.83548846754249', '2025-02-07 18:12:14', '2025-02-11 20:38:09', '1', 1, 'Construcción de una infraestructura para el apoyo logístico, operativo y productivo para las actividades del territorio. En un territorio insular aislado como Juan Fernández, un galpón portuario no es solo un espacio de almacenamiento, sino una infraestructura clave que permite garantizar la continuidad de las actividades económicas, el abastecimiento de la comunidad, la respuesta ante emergencias y la sostenibilidad del entorno. Su rol es fundamental para mejorar la calidad de vida, reducir los costos logísticos y fortalecer la resiliencia de la comunidad ante su aislamiento geográfico.'),
(71, 5, 'Convivencia y cohesión social', 'Participación comunitaria', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Crear espacios de participación ciudadana que fomenten el diálogo y la colaboración entre los diferentes actores sociales y comunitarios.', 'a', 'Estudio', '5.1', 'Plan territorial de participación comunitaria inspirado en Ciudades Amigables.', 'Ejecución', 'Ejecutado', NULL, NULL, 24300, '24300.00', '8% FNDR, DOS del MSGG, Presupuesto Municipal', 'DIDECO', 'División de Organizaciones Social, Ministerio Secretaría General de Gobierno.', NULL, '1', 'En espera', '0.00', NULL, '-33.63735960810802', '-78.83396863472', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'La comunidad, a través de un plan participativo, se involucra en un proceso de planificación orientado al desarrollo territorial. Este proceso busca tomar decisiones que reflejen tanto las necesidades y aspiraciones locales como los principios de la iniciativa de \"ciudades amigables\" promovida por la OMS. En particular, la comunidad organizada, liderada por el COSOC, trabajará para que las localidades de San Juan Bautista y Alejandro Selkirk materialicen su desarrollo urbano-territorial. La iniciativa apunta a generar un entorno con servicios y estructuras físicas inclusivas, adaptadas a las necesidades de toda la población, mejorando así la calidad de vida de todas las personas y promoviendo un ambiente más amigable y habitable para todos.'),
(72, 5, 'Convivencia y cohesión social', 'Organizaciones comunitarias', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Crear espacios de participación ciudadana que fomenten el diálogo y la colaboración entre los diferentes actores sociales y comunitarios.', 'b', 'Programa', '5.2', 'Programa de fortalecimiento de la red social y la generación de nuevos liderazgos.', 'Ejecución', 'Ejecutado', NULL, NULL, 11200, '11200.00', 'División de Organizaciones Sociales DOS, Presupuesto Municipal', 'DIDECO', 'División de Organizaciones Sociales del Ministerio Secretaría General de Gobierno.', NULL, '1', 'En espera', '0.00', NULL, '-33.639360489716985', '-78.83243513806633', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Iniciativa orientada a la capacitación de dirigentes sociales en diversos ámbitos de su quehacer, tales como: la ley que los rige, roles, funciones, gestión y liderazgo de la organización, con el propósito de desarrollar sus competencias y conocimientos en herramientas de gestión, formulación y evaluación de proyectos01, contabilidad básica, resolución de conflictos; como también motivar el recambio dirigencial.'),
(73, 5, 'Convivencia y cohesión social', 'Organizaciones comunitarias', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Crear espacios de participación ciudadana que fomenten el diálogo y la colaboración entre los diferentes actores sociales y comunitarios.', 'b', 'Programa', '5.3', 'Programa de fortalecimiento del voluntariado y redes de apoyo local.', 'Ejecución', 'Ejecutado', NULL, NULL, 11200, '11200.00', 'Ministerio de Desarrollo Social y de Familia.  Programa Local de Apoyo y Cuidados. Presupuesto Municipal.', 'DIDECO', 'SENAMA, SENADIS.', NULL, '1', 'En espera', '0.00', NULL, '-33.641054132536624', '-78.8363534749726', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Personas de la comunidad realizan en forma voluntaria actividades de apoyo a personas con dificultades de movilidad, se trata de determinar y reconocer esta labor mediante capacitación, organización y recursos para un funcionamiento más efectivo, iniciando un proceso de formalización y formación de un grupo de personas que voluntariamente realiza tareas de apoyo a otras personas.  Para ello, estructurar este grupo de personas que, en conjunto con instancias municipales (consultorio, asistencia social), apoyen en resolver problemas de personas enfermas, con discapacidad, personas mayores y, en general vulnerables.');
INSERT INTO `proyectos01` (`id`, `cod_area`, `area`, `subarea`, `origen`, `lineamiento`, `objetivos`, `cod_tipo`, `tipo`, `cod_iniciativa`, `nombre`, `etapa`, `meta_del_periodo`, `p_diseno`, `p_prefactibilidad`, `p_ejecucion`, `total`, `financiamiento`, `unidad`, `entidades_relacionadas`, `prioridad`, `cod_estado`, `estado`, `avance_actividades`, `avance_financiero`, `lat`, `lng`, `proyectos01_created`, `proyectos01_updated`, `proyectos01_user`, `proyectos01_status`, `descripcion`) VALUES
(74, 5, 'Convivencia y cohesión social', 'Equipamiento', 'Cartera Actual', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Crear espacios de participación ciudadana que fomenten el diálogo y la colaboración entre los diferentes actores sociales y comunitarios.', 'c', 'Proyecto', '5.4', 'Construcción de la sede de la juventud robinsoniana.', 'Ejecución', 'Ejecutado', NULL, NULL, 193990, '193990.00', 'FRIL GORE', 'SECPLA ', NULL, NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.636288979325805', '-78.83418071576472', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Construcción de una sede para la juventud robinsoniana, una agrupación juvenil perteneciente a la comuna de Juan Fernández. Se trata de la comunidad más joven de la isla que ha sido un grupo humano sumamente importante en su época de apogeo, el cual en su momento fue registrado bajo el nombre “JURO (juventud robinsoniana)”. Se conformó el 20 de febrero del 2001.'),
(75, 5, 'Convivencia y cohesión social', 'Equipamiento', 'Cartera Actual', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Crear espacios de participación ciudadana que fomenten el diálogo y la colaboración entre los diferentes actores sociales y comunitarios.', 'c', 'Proyecto', '5.5', 'Adquisición del DOMO de la mujer. ', 'Ejecución', 'Ejecutado', NULL, NULL, 77256, '77256.00', 'Circular 33, subtítulo 29 GORE', 'SECPLA ', NULL, NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.63465866061201', '-78.83513837035294', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Adquisición de una lona y piso para la estructura que conforma el domo de la mujer.'),
(76, 5, 'Convivencia y cohesión social', 'Programas sociales', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'a', 'Estudio', '5.6', 'Plan comunal de inclusión de las divergencias.', 'Ejecución', 'Ejecutado', NULL, NULL, 25000, '25000.00', 'FNDR, Programas MIDESOF, Presupuesto Municipal', 'DIDECO', 'Ministerio Secretaría General de Gobierno, MIDESOF', NULL, '1', 'En espera', '0.00', NULL, '-33.637100767795715', '-78.8341360845529', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio dirigido a generar información sobre la situación de las personas divergentes de la comuna, para entender y documentar las experiencias, necesidades y barreras que enfrentan en diferentes aspectos de sus vidas cotidianas en educación, trabajo, salud, convivencia social.'),
(77, 5, 'Convivencia y cohesión social', 'Comunicaciones', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'b', 'Programa', '5.7', 'Programas radiales de comunicaciones y de sensibilización sobre la convivencia social (fortalecimiento de radio local).', 'Ejecución', 'Ejecutado', NULL, NULL, 8800, '8800.00', 'Fondo de medios de comunicación social. Presupuesto Municipal', 'Comunicaciones', 'Ministerio Secretaría General de Gobierno', NULL, '1', 'En espera', '0.00', '0.00', '-33.64136437580009', '-78.83230880028938', '2025-02-07 18:12:14', '2025-02-13 22:25:26', '1', 1, 'Ciclos de programas y cápsulas radiales orientados a sensibilizar e informar sobre temas y aspectos relacionados a la convivencia social. El programa podría contemplar: i) sensibilización mediante cápsulas radiales, ii) foros y diálogos temáticos específicos; y iii) programas temáticos en profundidad con entrevistas a especialistas.'),
(78, 5, 'Convivencia y cohesión social', 'Programas sociales', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'b', 'Programa', '5.8', 'Programa de salud mental para infanto adolescente.', 'Ejecución', 'Ejecutado', NULL, NULL, 33000, '33000.00', 'MINSAL, FNDR, Presupuesto Municipal', 'DIDECO', 'MINSAL', NULL, '1', 'En espera', '0.00', NULL, '-33.63411645016786', '-78.83244600871471', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Desarrollo de un propuesta para ser presentado en las instancias correspondientes para la incorporación de un profesional de la salud mental que se encargue de atender a la población infantil y adolescente basado en un programa de intervención que comprenda: diagnóstico, atención clínica, desarrollo de iniciativas de apoyo –como terapias de juego, trabajos grupales que orienten y fomenten al autocuidado y compartir experiencias--, actividades de prevención de trastornos mentales y el desarrollo de habilidades para la gestión emocional, en un entorno seguro y de sustento.'),
(79, 5, 'Convivencia y cohesión social', 'Cuidados', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'a', 'Estudio', '5.9', 'Plan de atención integral para personas con movilidad reducida.', 'Ejecución', 'Ejecutado', NULL, NULL, 18000, '18000.00', 'Ministerio de Desarrollo Social, Programa red local de apoyo y cuidados. SENADIS, presupuesto municipal.', 'DIDECO', 'Ministerio de Desarrollo Social, SENAMA, SENADIS. Servicio de Salud.', NULL, '1', 'En espera', '0.00', NULL, '-33.637929497998364', '-78.83212224924392', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio orientado a generar un plan para otorgar cuidado a las personas con movilidad reducida que carezcan de una adecuada red de apoyo. El estudio propondrá soluciones articuladas de los diversos aspectos a considerar (integralidad de la propuesta resultante), abordando ámbitos tales como: requerimientos en la vivienda, equipamiento, soportes tecnológicos, cuidados físicos, soporte psicosocial.  '),
(80, 5, 'Convivencia y cohesión social', 'Infraestructura de cuidados', 'PLADECO', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'c', 'Proyecto', '5.10', 'Construcción de centro de cuidados y emergencia, etapa de diseño.', 'Perfil', 'Diseño ejecutado', 70000, NULL, NULL, '70000.00', 'SERVIU', 'DIDECO / DOM', 'DOM / SERVIU', NULL, '1', 'En espera', '0.00', NULL, '-33.64305371134439', '-78.83119470277873', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio de diseño para establecer el conjunto de requerimientos para la construcción de un centro de cuidado destinado a personas cuidadoras y personas que requieren cuidados. Esta futura infraestructura multipropósito permitirá la realización de actividades recreativas y culturales, el desarrollo de actividades al aire libre. Se tratará de un recinto multipropósito que tendría 250 m², sismorresistente y con autonomía de 120 horas ante catástrofes. Contribuirá a la situación de personas con dependencia moderada o severa, cuyo cuidado está, en su gran mayoría, a cargo de mujeres con escasa infraestructura de apoyo. Esta situación de dependencia es muy sensible ante emergencias y catástrofes, recurrentes en nuestro país.'),
(81, 5, 'Convivencia y cohesión social', 'Seguridad publica comunal', 'Cartera Actual', '1. Comunidad comprometida con la participación cívica y vínculos que respeta la convivencia social.', 'Incrementar las habilidades que contribuyen al respeto de los derechos fundamentales, la tolerancia y el desarrollo del territorio y sus habitantes.', 'c', 'Proyecto', '5.11', 'Sistema de tele protección para la comuna de Juan Fernández', 'Ejecución', 'Ejecutado', NULL, NULL, 50000, '50000.00', 'Subsecretaria de prevención del delito, Ministerio del interior y seguridad Pública', 'SECPLA ', NULL, NULL, '4', 'En licitación', '0.00', NULL, '-33.63981882138248', '-78.83586143310067', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Proyecto de tele protección y vigilancia, para la comuna de juan Fernández que pueda ayudar a prevenir el delito en zonas asociados al acoso escolar, consumo de drogas e incivilidades. El proyecto contempla sala de televigilancia, antenas y cámaras de televigilancia.'),
(82, 6, 'Acceso a servicios', 'Comercialización', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'b', 'Programa', '6.1', 'Digitalización de la gestión en salud.', 'Ejecución', 'Ejecutado', 0, 0, 150000, '150000.00', 'FNDR, Ministerio de salud', 'SECPLA', 'Ministerio de Salud de Chile, Servicio de Salud Valparaíso-San Antonio, Subsecretaría de Redes Asist', '', '1', 'En espera', '0.00', '0.00', '-33.636388369660516', '-78.83599583778656', '2025-02-07 18:12:14', '2025-02-14 21:08:14', '1', 1, 'Implementar un sistema digital para la gestión de fichas médicas y el seguimiento de controles de salud en la comuna de Juan Fernández. El programa busca mejorar la eficiencia en el manejo de la información médica, facilitar el acceso a datos clínicos y optimizar la continuidad del cuidado, especialmente en una zona geográficamente aislada con acceso limitado a especialistas. Para lograr esto, resulta imprescindible una mejora en la conectividad que permita aumentar la capacidad en la transmisión de datos, así como disminuir la latencia para asegurar la continuidad del servicio.'),
(83, 6, 'Acceso a servicios', 'Infraestructura y tecnologías para la salud', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'b', 'Programa', '6.2', 'Dotación de equipamiento especialista  y telemedicina.', 'Ejecución', 'Ejecutado', NULL, NULL, 250000, '250000.00', 'FNDR, Ministerio de salud', 'SECPLA', 'Ministerio de Salud de Chile, Servicio de Salud Valparaíso-San Antonio, Subsecretaría de Redes Asist', NULL, '1', 'En espera', '0.00', '0.00', '-33.638196661207196', '-78.83530150976803', '2025-02-07 18:12:14', '2025-02-10 23:44:18', '1', 1, 'Implementar un programa para mejorar la dotación de equipamiento médico especializado que cumple su vida útil o presenta deterioro debido al bajo mantenimiento y fortalecer el uso de telemedicina en la comuna de Juan Fernández. Este programa busca optimizar la atención médica mediante la adquisición de equipos esenciales y la implementación de tecnologías que faciliten consultas con especialistas a distancia, mejorando así la cobertura y calidad del servicio en una zona con baja frecuencia de operativos médicos.'),
(84, 6, 'Acceso a servicios', 'Formación y fortalecimiento de capacidades', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'b', 'Programa', '6.3', 'Programa de pasantía en salud en áreas clave.', 'Ejecución', 'Ejecutado', NULL, NULL, 200000, '200000.00', 'Fondo Nacional de Desarrollo Regional (FNDR) y convenios con universidades.', 'SECPLA', 'Ministerio de Salud de Chile, Servicio de Salud Valparaíso-San Antonio, Universidades y centros de f', NULL, '1', 'En espera', '0.00', NULL, '-33.637150753029985', '-78.83381715385876', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El programa busca atraer profesionales de la salud para que realicen pasantías en la comuna de Juan Fernández, con el objetivo de mejorar la atención médica en áreas clave, como kinesiólogo, químico farmacéuticos, enfermeros. La iniciativa también contempla la formación continua del personal local mediante el intercambio de conocimientos y prácticas con los profesionales visitantes. El proyecto busca disponer de las condiciones para que los pasantes puedan permanecer en la isla financiado viajes, alojamiento y alimentación.'),
(85, 6, 'Acceso a servicios', 'Servicios Públicos', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'c', 'Proyecto', '6.4', 'Normalización del cementerio municipal, etapa de factibilidad.', 'Factibilidad', 'RS Diseño', NULL, NULL, 300000, '300000.00', 'FNDR', 'SECPLA', 'Ministerio de Salud, Gobierno Regional', NULL, '1', 'En espera', '0.00', NULL, '-33.638876738349516', '-78.83123962167295', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto busca realizar un estudio de factibilidad para la normalización del cementerio municipal, con el objetivo de mejorar la infraestructura, los servicios y el acceso al espacio. Esto incluye la evaluación de las condiciones actuales, la propuesta de nuevas instalaciones y servicios, y la planificación de un diseño que contemple la sostenibilidad y el respeto por el entorno natural, así como normalizar su funcionamiento de acuerdo con las normas sanitarias.'),
(86, 6, 'Acceso a servicios', 'Servicios Públicos', 'Cartera Actual', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'c', 'Proyecto', '6.5', 'Mejoramiento cementerio comunal, Poblado San Juan Bautista', 'Ejecución', 'Ejecutado', NULL, NULL, 45000, '45000.00', 'FRIL GORE', 'SECPLA Municipalidad de Juan Fernández', 'Ministerio de Salud, Gobierno Regional', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64321076840888', '-78.83437826917316', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto contempla el cierre perimetral del recinto, así como la adquisición de mobiliario urbano, construcción de tarimas y espacios de tránsito dentro del cementerio. Considera demolición parcial de infraestructura en mal estado, construcción de cierre perimetral, una pasarela de madera, construcción de módulos de madera, mobiliario urbano, realizar mantenimiento a la fuente de agua, construir una huella de adocreto y finalmente instalación de torniquetes de madera para el acceso. Esto ayuda a la puesta en valor de un espacio relevante de la comuna. Se ha licitado en dos oportunidades, sin recibir ofertas. '),
(87, 6, 'Acceso a servicios', 'Infraestructura de salud', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'c', 'Proyecto', '6.6', 'Construcción de sala de rehabilitación, comuna de Juan Fernández, etapa de factibilidad.', 'Factibilidad', 'RS Diseño', NULL, 50000, NULL, '50000.00', 'Ministerio de Salud, Gobierno Regional de Valparaíso, FNDR', 'Departamento de Salud Municipal Municipalidad de Juan Fernández', 'Ministerio de Salud, Gobierno Regional', NULL, '1', 'En espera', '0.00', NULL, '-33.634277742447274', '-78.83324649034716', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto busca desarrollar un estudio de prefactibilidad que evalúe la viabilidad de construir una sala de rehabilitación en la comuna de Juan Fernández. Este espacio proporcionará servicios de rehabilitación física y atención de salud para la población, particularmente útil para aquellos con movilidad reducida o que requieren de atención prolongada por parte de profesionales especialistas.'),
(88, 6, 'Acceso a servicios', 'Infraestructura de salud', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'c', 'Proyecto', '6.7', 'Construcción de laboratorio clínico, comuna de Juan Fernández, etapa de factibilidad.', 'Factibilidad', 'Ejecutado factibilidad', NULL, 50000, NULL, '50000.00', 'Ministerio de Salud, Gobierno Regional de Valparaíso, FNDR', 'Departamento de Salud Municipal Municipalidad de Juan Fernández', 'Ministerio de Salud, Gobierno Regional', NULL, '1', 'En espera', '0.00', NULL, '-33.633844733979956', '-78.83516493961434', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto busca realizar un estudio de prefactibilidad para la construcción de un laboratorio clínico que permita realizar análisis y exámenes en la comuna de Juan Fernández, mejorando significativamente la capacidad de respuesta en salud. Actualmente, el pequeño laboratorio del consultorio general rural no logra cubrir las necesidades de la comunidad y enfrenta limitaciones que resultan en la pérdida de muestras debido a las dificultades de traslado al continente.'),
(89, 6, 'Acceso a servicios', 'Infraestructura de salud', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Proveer servicios de salud eficientes, accesibles y de calidad, adaptados a las características geográficas de Juan Fernández.', 'c', 'Proyecto', '6.8', 'Hospital comunitario, comuna de Juan Fernández, etapa de prefactibilidad.', 'Prefactibilidad', 'Ejecutado pre / factibilidad', NULL, 80000, NULL, '80000.00', 'Ministerio de Salud, Gobierno Regional de Valparaíso, FNDR', 'Departamento de Salud Municipal Municipalidad de Juan Fernández', 'Ministerio de Salud, Gobierno Regional', NULL, '1', 'En espera', '0.00', NULL, '-33.63973729369333', '-78.83659016996955', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto tiene como objetivo desarrollar un estudio de prefactibilidad para la construcción de un hospital comunitario en la comuna de Juan Fernández. Este hospital proporcionaría servicios de salud primaria ampliados y permitiría a la comunidad contar con una infraestructura capaz de ofrecer una gama completa de prestaciones, disminuyendo la dependencia de centros de salud en el continente. Actualmente, el consultorio general rural adapta servicios de hospitalización en casos de necesidad, aunque no está diseñado para tales fines, pudiendo entonces considerar la ampliación de la infraestructura para dar cabida a este tipo de recinto.'),
(90, 6, 'Acceso a servicios', 'Deporte y Recreación ', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'a', 'Estudio', '6.9', 'Plan comunal de deportes.', 'Ejecución', 'Ejecutado', NULL, NULL, 50000, '50000.00', 'Ministerio del Deporte, FNDR y municipales.', 'DIDECO Juan Fernández ', 'Ministerio del Deporte, Ministerio de Educación, Gobierno Regional de Valparaíso, Servicio de Salud ', NULL, '1', 'En espera', '0.00', NULL, '-33.64197441063301', '-78.8334859846985', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El \"Plan comunal de deportes\" busca desarrollar una estrategia integral para fomentar la práctica deportiva en la comuna de Juan Fernández. Dado el aislamiento geográfico y la infraestructura deportiva existente y en desarrollo, el estudio se enfocará en mejorar la oferta de actividades deportivas, optimizar el uso de instalaciones, espacio público y entorno natural, promoviendo la actividad física como herramienta de bienestar y cohesión social.'),
(91, 6, 'Acceso a servicios', 'Desarrollo comunitario', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'b', 'Programa', '6.10', 'Fortalecimiento de las capacidades de asociaciones deportivas y culturales.', 'Ejecución', 'Ejecutado', NULL, NULL, 150000, '150000.00', 'Fondo Nacional de Desarrollo Regional (FNDR), aportes municipales y fondos concursables del Ministerio del Deporte y la Cultura.', 'DIDECO o corporación con competencias sobre el tema', 'Ministerio del Deporte de Chile, Ministerio de las Culturas, las Artes y el Patrimonio, Gobierno reg', NULL, '1', 'En espera', '0.00', NULL, '-33.640914811218394', '-78.83272574373777', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El programa busca mejorar las capacidades organizativas y operativas de las asociaciones deportivas y culturales de la comuna de Juan Fernández, promoviendo la participación comunitaria y el desarrollo de actividades que fomenten el bienestar social, la identidad local y la cohesión social. Se contempla el apoyo en formación, acceso a recursos, gestión de proyectos01 y promoción de eventos.'),
(92, 6, 'Acceso a servicios', 'Salud y bienestar social', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'b', 'Programa', '6.11', 'Programa de educación sexual y afectiva.', 'Ejecución', 'Ejecutado', NULL, NULL, 80000, '80000.00', 'Ministerio de Educación, Ministerio de Salud, FNDR, Fondos municipales', 'DIDECO o corporación con competencias sobre el tema', 'Ministerio de Educación de Chile, Ministerio de Salud de Chile, Servicio Nacional de la Mujer y la E', NULL, '1', 'En espera', '0.00', NULL, '-33.638521234490156', '-78.83330131430769', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El programa tiene como objetivo implementar un plan integral de educación sexual y afectiva en la comuna de Juan Fernández, que aborde temas de salud sexual, relaciones afectivas saludables, prevención de enfermedades de transmisión sexual (ETS) y embarazo adolescente. La iniciativa busca fortalecer la educación en estos temas desde una perspectiva inclusiva y adaptada a la realidad local, considerando la pequeña población y el contexto insular.'),
(93, 6, 'Acceso a servicios', 'Innovación y Tecnología', 'PLADECO', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'b', 'Programa', '6.12', 'Programa para el fomento de habilidades y competencias digitales para NNA.', 'Ejecución', 'Ejecutado', NULL, NULL, 80000, '80000.00', 'Fondos regionales, Fondos municipales. Aportes de empresas tecnológicas o ONGs especializadas en educación digital.', 'DIDECO o corporación con competencias en el tema', 'Ministerio de Educación de Chile, Ministerio de Ciencia, Tecnología, Conocimiento e Innovación, Subs', NULL, '1', 'En espera', '0.00', NULL, '-33.6404525359921', '-78.83170304585921', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El programa tiene como objetivo desarrollar las habilidades y competencias digitales de los niños, niñas y adolescentes (NNA) de la comuna de Juan Fernández. La iniciativa busca proporcionarles herramientas para el uso seguro, responsable y creativo de las tecnologías, así como potenciar sus capacidades en áreas como programación, manejo de software, alfabetización digital y ciberseguridad. El enfoque se adapta a la realidad local y contempla actividades tanto presenciales como remotas, aprovechando las limitadas infraestructuras tecnológicas disponibles. Para la elaboración de este programa, tomar como referencia el programa CEIBAL de Uruguay.'),
(94, 6, 'Acceso a servicios', 'Infraestructura deportiva', 'Cartera Actual', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'c', 'Proyecto', '6.13', 'Construcción Gimnasio Municipal, etapa de ejecución.', 'Ejecución', 'Ejecutado', NULL, NULL, 5000000, '5000000.00', 'FNDR GORE', 'SECPLA Municipalidad de Juan Fernández', 'Ministerio de Vivienda, SERVIU, Gobierno Regional de Valparaíso', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.64188015817288', '-78.834908366056', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto de construcción de gimnasio municipal Juan Fernández, contempla la reposición de una infraestructura perdida tras el tsunami del año 2010. Esta nueva infraestructura se encuentra proyectada en el sector costero más bajo del poblado con destino deportivo en el respectivo instrumento de planificación territorial, donde se pretende concentrar el conjunto de equipamiento deportivo y recreativo de la comuna, junto al estadio, multicancha, sala deportiva, sedes de clubes deportivos y la futura zona recreativa, la que integrará todos estos espacios. Se trata de una obra de 1.474 mt2. Actualmente se está ejecutando el diseño del gimnasio, a través de un contrato licitado por un monto de $211.497.997 IVA Incluido, financiado a través del programa para pequeñas localidades del Ministerio de Vivienda y Urbanismo, específicamente a través del SERVIU.'),
(95, 6, 'Acceso a servicios', 'Infraestructura deportiva', 'Cartera Actual', '1. Comunidad con acceso oportuno y de calidad a la salud.', 'Consolidar una oferta de servicios sociales diversos y pertinentes para la comunidad de Juan Fernández.', 'c', 'Proyecto', '6.14', 'Construcción techado multicancha. ', 'Ejecución', 'Ejecutado', NULL, NULL, 315000, '315000.00', 'FNDR GORE', 'SECPLA Municipalidad de Juan Fernández', 'Gobierno Regional de Valparaíso', NULL, '5', 'Etapa en ejecución', '0.00', NULL, '-33.642155049938694', '-78.83268875413701', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'El proyecto contempla la construcción del techo de la multicancha de la comuna, la que no cuenta con las condiciones para acoger la actividad deportiva y recreativa en condiciones climáticas más adversas. La multichancha se emplaza en lo que conformará la zona recreativa de la comuna, junto con otro equipamiento deportivo. '),
(96, 7, 'Cultura, identidad y patrimonio ', 'Participación cultural', 'PLADECO', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Integración del patrimonio natural, histórico y cultural del archipiélago como bases de desarrollo comunitario.', 'b', 'Programa', '7.1', 'Programa Celebración Aniversario del Archipiélago de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 69000, '69000.00', 'MINCAP, Presupuesto Municipal', 'Unidad de Cultura Municipalidad de Juan Fernández', 'Subsecretaría de las Culturas y las Artes MINCAP, Secretaría Regional Ministerial MINCAP', NULL, '1', 'En espera', '0.00', NULL, '-33.63452939386197', '-78.8327145982915', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Realización de acciones enfocadas en mejorar la organización, la participación, la promoción, el equipamiento y el impacto económico de las festividades. Incluye las siguientes acciones: 1) Investigación y documentación, 2) Capacitación y fortalecimientos de las organizaciones para la autogestión, 3) Mejora de la programación, 4) Equipamiento, 5) Sostenibilidad económica.'),
(97, 7, 'Cultura, identidad y patrimonio ', 'Infraestructura cultural', 'Cartera Actual', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Integración del patrimonio natural, histórico y cultural del archipiélago como bases de desarrollo comunitario.', 'c', 'Proyecto', '7.2', 'Restauración de Monumentos Históricos y Arqueológicos Fuerte Santa Bárbara y Cueva de los Patriotas, etapa de ejecución.', 'Ejecución', 'En ejecución', NULL, NULL, 3141439, '3141439.00', 'Dirección de Arquitectura – MOP', 'SECPLA Municipalidad de Juan Fernández', 'Dirección de Arquitectura - MOP, SUBDERE, GORE', NULL, '2', 'Formulada', '0.00', NULL, '-33.63865936093907', '-78.83380586657437', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Consiste en realizar la restauración de los dos sitios del monumento histórico de acuerdo con el diseño realizado, para lo cual requiere resolver previamente dar por finalizado el comodato que el ministerio de Bienes Nacionales tiene vigente con el Ministerio de Defensa para la instalación de las oficinas de la DGAC que todavía funcionan en el terreno, incluyendo una antena de comunicaciones. Debido a que ha transcurrido bastante tiempo desde que se realizó el diseño, se deberá actualizar para verificar que el levantamiento crítico y las intervenciones estén vigentes.'),
(98, 7, 'Cultura, identidad y patrimonio ', 'Infraestructura cultural', 'PLADECO', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Integración del patrimonio natural, histórico y cultural del archipiélago como bases de desarrollo comunitario.', 'c', 'Proyecto', '7.3', 'Restauración de la Casa de Piedra de Alejandro Selkirk, etapa perfil de diseño.', 'Perfil', 'RS Diseño', 31000, NULL, NULL, '31000.00', 'Subsecretaría del Patrimonio Cultural, FNDR', 'SECPLA Municipalidad de Juan Fernández', 'Dirección de Arquitectura MOP', NULL, '1', 'En espera', '0.00', NULL, '-33.6342681816674', '-78.83493108863452', '2025-02-07 18:12:14', '2025-02-11 20:52:22', '1', 1, 'Relacionada con Alexander Selkirk, cuya historia inspiró \"Robinson Crusoe\", el sitio fue revelado científicamente de manera reciente, pero es conocido localmente desde hace tiempo. El sitio está relacionado con la estancia del marinero escocés Alexander Selkirk, quien fue abandonado en la isla Robinson Crusoe en 1704 y rescatado cuatro años después. Su historia inspiró la novela \"Robinson Crusoe\" de Daniel Defoe. La iniciativa consiste en realizar los estudios básicos para postular a diseño el proyecto de restauración del monumento histórico definiendo los términos de referencia de todas las especialidades involucradas. De manera complementaria es posible realiza las gestiones para lograr la declaratoria legal de patrimonio inmueble como monumento nacional.'),
(99, 7, 'Cultura, identidad y patrimonio ', 'Gestión cultural', 'PLADECO', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Generación de un espacio de colaboración para el desarrollo de proyectos01 culturales.', 'a', 'Estudio', '7.4', 'Plan de Gestión de Infraestructuras Culturales.', 'Ejecución', 'Ejecutado', NULL, NULL, 21000, '21000.00', 'FNDR, Presupuesto municipal', 'Unidad de Cultura Municipalidad de Juan Fernández', 'Subsecretaría de las Culturas y las Artes MINCAP, Secretaría Regional Ministerial MINCAP', NULL, '1', 'En espera', '0.00', NULL, '-33.6367528817838', '-78.83357137461607', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Realizar un proceso de planificación estratégica a nivel comunal para definir estrategias para la gestión de las infraestructuras culturales, los desafíos de mediano plazo, el desarrollo de la cadena de valor cultural a nivel local, la línea editorial, el modelo de financiamiento, la estructura y el perfil profesional de la gestión. Se busca contar con un plan de gestión alineado con las políticas públicas y que incorpore las nuevas tendencias de la gestión cultural basado en la creación de entornos colaborativos.'),
(100, 7, 'Cultura, identidad y patrimonio ', 'Infraestructura cultural', 'Cartera Actual', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Generación de un espacio de colaboración para el desarrollo de proyectos01 culturales.', 'c', 'Proyecto', '7.5', 'Biblioteca Municipal de Juan Fernández, etapa de ejecución.', 'Ejecución', 'Ejecutado', 185383, NULL, 1500000, '1685383.00', 'FNDR GORE', 'SECPLA Municipalidad de Juan Fernández', 'Subsecretaría de las Culturas y las Artes MINCAP, Secretaría Regional Ministerial MINCAP', NULL, '3', 'Postulada a financiamiento', '0.00', NULL, '-33.638268852075115', '-78.83636236557136', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Ejecutar la “Construcción de la Biblioteca Pública N°331 “Daniel Defoe” del Archipiélago de Juan Fernández”. La finalidad de esta iniciativa es la recuperación total de la “Casa de la Cultura de Juan Fernández”, tras ser abatida por el tsunami del 2010.'),
(101, 7, 'Cultura, identidad y patrimonio ', 'Infraestructura cultural', 'PLADECO', '1. Un polo cultural local basado en el patrimonio e identidad del archipiélago, que potencia las capacidades creativas de la comunidad.', 'Generación de un espacio de colaboración para el desarrollo de proyectos01 culturales.', 'c', 'Proyecto', '7.6', 'Construcción Centro Cultural de Juan Fernández, etapa perfil de diseño.', 'Perfil', 'RS Diseño', 36000, NULL, NULL, '36000.00', 'MINCAP, Presupuesto Municipal', 'SECPLA Municipalidad de Juan Fernández', 'Subsecretaría de las Culturas y las Artes MINCAP, Secretaría Regional Ministerial MINCAP', NULL, '1', 'En espera', '0.00', NULL, '-33.6352417704108', '-78.8305822675014', '2025-02-07 18:12:14', '2025-02-11 20:52:35', '1', 1, 'Realizar los estudios de prefactibilidad para postular a la etapa de factibilidad o diseño el proyecto de centro cultural para la comuna de Juan Fernández, definiendo tamaño, programa de servicios, localización, materialidad de la infraestructura y modelo de gestión.'),
(102, 8, 'Mejoramiento Institucional', 'Estructura interna', 'PLADECO', '1. Organización con orientación activa al ciudadano, empoderando su participación y colaboración.', 'Mejorar los servicios que la municipalidad presta a la ciudadanía por medio de la implementación de mejora de procesos, sistemas y planes de trabajo en equipo.', 'a', 'Estudio', '8.1', 'Planificación de organigrama y dotación municipal. ', 'Ejecución', 'Ejecutado', NULL, NULL, 50000, '50000.00', 'Fondos regionales. Fondos municipales. SUBDERE', 'Dirección de Administración y Finanzas', 'SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.63982921538054', '-78.83127543103961', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Estudio dirigido a generar un plan para la ampliación de las direcciones y/o departamentos del Municipio'),
(103, 8, 'Mejoramiento Institucional', 'Digitalización', 'PLADECO', '1. Organización con orientación activa al ciudadano, empoderando su participación y colaboración.', 'Modernizar y optimizar los procesos de atención a usuarias y usuarios municipales.', 'b', 'Programa', '8.2', 'Programa transformación digital de la Municipalidad de Juan Fernández.', 'Ejecución', 'Ejecutado', NULL, NULL, 135000, '135000.00', 'Fondos regionales. Fondos municipales. SUBDERE', 'Dirección de Administración y Finanzas', 'Gobierno Digital, SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.64061581096415', '-78.83187882781672', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Diseñar e implementar un plan de gestión del cambio para apoyar el proceso de Transformación Digital de la Municipalidad de Juan Fernández conforme a la Ley de Transformación Digital del Estado de Chile.'),
(104, 8, 'Mejoramiento Institucional', 'Cultura', 'PLADECO', '2. Organización que inspira a sus colaboradores internos municipales a trabajar acorde a los nuevos valores esenciales', 'Adherir los valores esenciales institucionales en los colaboradores municipales.', 'b', 'Programa', '8.3', 'Programa de desarrollo cultural.', 'Ejecución', 'Ejecutado', NULL, NULL, 217500, '217500.00', 'Fondos regionales. Fondos municipales. SUBDERE', 'Dirección de Administración y Finanzas', 'SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.64267877078009', '-78.83064613542994', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Diseñar un programa que permita instalar en el Municipio los nuevos valores culturales.'),
(105, 8, 'Mejoramiento Institucional', 'Infraestructura', 'PLADECO', '2. Organización que inspira a sus colaboradores internos municipales a trabajar acorde a los nuevos valores esenciales', 'Mejorar instalaciones y equipamiento del personal municipal, que posibilite el desarrollo de los valores esenciales de la municipalidad.', 'c', 'Proyecto', '8.4', 'Construcción Edificio Municipal, etapa perfil de diseño.', 'Perfil', 'RS Diseño', NULL, NULL, 26000, '26000.00', 'FNDR, Presupuesto Municipal', 'SECPLA Municipalidad de Juan Fernández', 'GORE', NULL, '1', 'En espera', '0.00', NULL, '-33.63692278242368', '-78.83408820562659', '2025-02-07 18:12:14', '2025-02-11 20:52:47', '1', 1, 'Realizar los estudios de prefactibilidad para postular a la etapa de factibilidad o diseño el proyecto de construcción del nuevo edificio municipal para la comuna de Juan Fernández. La realización del proyecto requiere contar con un diagnóstico de la edificación no concluida del proyecto anterior '),
(106, 8, 'Mejoramiento Institucional', 'Clima organizacional', 'PLADECO', '2. Organización que inspira a sus colaboradores internos municipales a trabajar acorde a los nuevos valores esenciales', 'Mejorar la motivación y calidad de clima laboral del personal municipal.', 'b', 'Programa', '8.5', 'Programa de mejora de clima organizacional.', 'Ejecución', 'Ejecutado', NULL, NULL, 45500, '45500.00', 'Fondos regionales. Fondos municipales. SUBDERE', 'Dirección de Administración y Finanzas', 'SUBDERE', NULL, '1', 'En espera', '0.00', NULL, '-33.64154739143228', '-78.83307665914933', '2025-02-07 18:12:14', '2025-02-10 23:39:28', '1', 1, 'Diseñar un programa que permita instalar en el Municipio los nuevos valores culturales.');
